-- Schema for Domain: compliance | Business: Oil Gas | Version: v1_mvm
-- Generated on: 2026-05-04 09:29:07

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `oil_gas_ecm`.`compliance` COMMENT 'Manages regulatory reporting, permits, licenses, and adherence to federal and state regulations including SEC reserves disclosure, EPA environmental filings, BSEE offshore reports, FERC pipeline tariffs, PHMSA safety reports, BOEM offshore permits, and OPEC quota compliance. Owns regulatory submissions, permit registers, compliance calendars, audit trails, compliance certifications, violation tracking, and government reporting obligations. Supports SOX internal controls and ESG reporting.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `oil_gas_ecm`.`compliance`.`regulatory_filing` (
    `regulatory_filing_id` BIGINT COMMENT 'Unique surrogate identifier for each regulatory filing record in the Oil Gas compliance data product. Primary key for the regulatory_filing entity. Role: TRANSACTION_HEADER.',
    `afe_budget_id` BIGINT COMMENT 'Foreign key linking to procurement.afe_budget. Business justification: Regulatory filings for capital projects (drilling permits, facility approvals) tied to AFE for project cost tracking. Real business process: project regulatory compliance budgeting. Links filing costs',
    `asset_facility_id` BIGINT COMMENT 'Foreign key linking to asset.asset_facility. Business justification: Regulatory filings (Tier II, TRI, SPCC, Title V annual compliance certifications) are submitted for specific facilities. Direct facility FK on regulatory_filing enables facility-level filing tracking ',
    `calendar_id` BIGINT COMMENT 'Reference to the compliance calendar entry or obligation record that triggered or is associated with this regulatory filing. Links the filing to the scheduled compliance obligation in the compliance calendar management system, supporting deadline tracking and obligation fulfillment reporting.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Regulatory filing costs (preparation, submission fees, legal counsel) are allocated to cost centers for compliance budget tracking and SOX control over regulatory spend. Essential for variance analysi',
    `counterparty_id` BIGINT COMMENT 'Foreign key linking to customer.customer_counterparty. Business justification: Counterparties (JV partners, PSA contractors, operators) submit regulatory filings as legal entities. Real process: tracking which counterparty submitted each filing for joint venture reporting, PSA c',
    `crude_grade_id` BIGINT COMMENT 'Foreign key linking to product.crude_grade. Business justification: Export licenses, customs declarations, PSA/concession royalty filings, and OPEC quota reporting require specific crude grade identification. Critical for international trade compliance and production ',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Regulatory filings often prepared/submitted by external legal or regulatory consulting firms tracked as vendors. Real business process: outsourced regulatory submission services procurement. Replaces ',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Filing fees, penalties, and accruals trigger journal entries requiring GL account mapping for financial statement preparation, SEC reporting, and audit trail. Critical for matching filing_fee_amount a',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: A regulatory filing fulfills a specific compliance obligation (e.g., an SEC reserves disclosure filing fulfills the annual reserves reporting obligation, an EPA GHG report fulfills the GHG reporting o',
    `original_filing_compliance_regulatory_filing_id` BIGINT COMMENT 'Reference to the original regulatory_filing record that this amendment or superseding filing corrects or replaces. Null for original (non-amendment) filings. Enables amendment chain tracking and audit trail for regulatory corrections.',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: A regulatory filing may be associated with a specific permit (e.g., a permit renewal application filing, an emission report filed under a specific air permit, a BOEM drilling report filed under a spec',
    `petroleum_product_id` BIGINT COMMENT 'Foreign key linking to product.petroleum_product. Business justification: Regulatory filings require petroleum product identification for EPA fuel registrations, emissions reporting (carbon intensity by product), state fuel quality compliance programs, and export/import cus',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Regulatory filings require profit center allocation for SEC segment disclosures, reserves reporting by segment, and internal management reporting. Essential for segment P&L attribution and financial s',
    `regulatory_authority_id` BIGINT COMMENT 'Reference to the governing body or regulatory authority to which this filing is submitted (e.g., SEC, EPA, BSEE, FERC, PHMSA, BOEM, OSHA, state oil and gas commission). Serves as the PARTY_REFERENCE for this transaction, linking to the regulatory authority master record.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Regulatory filings (SEC reserves, OPEC quota, environmental reports) are submitted by legal entities tracked as accounts. Real business process: entity-level regulatory reporting requires linking fili',
    `acknowledgment_date` DATE COMMENT 'The date on which the regulatory authority officially acknowledged or confirmed receipt of the filing. May differ from submission_timestamp if the authority processes submissions on a batch or business-day basis. Used to confirm the filing entered the authoritys system of record.',
    `acknowledgment_reference` STRING COMMENT 'The official confirmation or acknowledgment reference number issued by the regulatory authority upon receipt of the filing (e.g., SEC EDGAR accession number, BSEE confirmation number, EPA CDX submission ID, FERC docket number). Serves as the authoritative proof of submission for audit and legal purposes.',
    `confidentiality_treatment` STRING COMMENT 'Indicates the confidentiality treatment status of this regulatory filing. Some filings contain commercially sensitive data (e.g., proprietary seismic data in BOEM permits, trade secret process information in EPA permits) for which the company may request confidential treatment from the regulatory authority.. Valid values are `public|confidential_treatment_requested|confidential_treatment_granted|restricted`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this regulatory filing record was first created in the compliance data system. Serves as the RECORD_AUDIT_CREATED field for audit trail purposes. Distinct from submission_timestamp which records the actual regulatory submission event.',
    `document_version` STRING COMMENT 'Version number of the regulatory filing document submitted (e.g., 1.0 for initial submission, 2.0 for amendment, 3.0 for second amendment). Supports document versioning and amendment tracking across the filing lifecycle.. Valid values are `^[0-9]+.[0-9]+$`',
    `due_date` DATE COMMENT 'The regulatory deadline by which this filing must be submitted to the governing authority. Used for compliance calendar management, deadline monitoring, and on-time filing performance tracking. Compared against submission_timestamp to determine if the filing was timely.',
    `enablon_submission_code` STRING COMMENT 'The source system submission identifier from Enablon HSE Management platform, used for HSE-related regulatory filings (incident reports, permit to work submissions, environmental compliance filings, audit reports). Enables traceability back to the originating Enablon record for data lineage.',
    `esg_reporting_flag` BOOLEAN COMMENT 'Indicates whether this regulatory filing contributes to or is part of the companys Environmental, Social, and Governance (ESG) reporting obligations. True for GHG emissions reports, environmental compliance filings, and sustainability disclosures. Supports ESG portfolio tracking and investor reporting.',
    `filing_category` STRING COMMENT 'High-level domain category of the regulatory filing, used for portfolio-level compliance tracking and reporting. Distinguishes between reserves disclosure (SEC), environmental compliance (EPA), offshore safety (BSEE), pipeline safety (PHMSA), tariff regulation (FERC), offshore permitting (BOEM), production quota (OPEC), and HSE reporting (OSHA). [ENUM-REF-CANDIDATE: reserves_disclosure|environmental|offshore_safety|pipeline_safety|tariff|permit|quota|hse|financial|operational|land|joint_venture — promote to reference product]',
    `filing_description` STRING COMMENT 'Free-text description of the regulatory filing, including its purpose, scope, key data reported, and any special circumstances or notes relevant to compliance officers and auditors. Provides context beyond the structured classification fields.',
    `filing_fee_amount` DECIMAL(18,2) COMMENT 'The monetary fee paid to the regulatory authority for processing this filing, where applicable (e.g., SEC registration fees, BOEM permit application fees, state commission filing fees). Expressed in the currency specified by filing_fee_currency. Zero or null for filings with no associated fee.',
    `filing_fee_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the filing fee amount (e.g., USD for US dollar, GBP for British pound, EUR for euro). Required when filing_fee_amount is non-zero to support multi-currency international regulatory filings.. Valid values are `^[A-Z]{3}$`',
    `filing_number` STRING COMMENT 'Externally-known unique reference number assigned to this regulatory submission, as issued by the submitting entity or the regulatory authority (e.g., SEC accession number, BSEE incident report number, EPA facility ID submission reference, FERC docket number). Serves as the BUSINESS_IDENTIFIER for this transaction.',
    `filing_period_end_date` DATE COMMENT 'The end date of the reporting period covered by this regulatory filing. For SEC 10-K reserves disclosures, this is the fiscal year-end date (typically December 31). For BSEE production reports, this is the month-end date. Used to validate that the filing covers the required reporting window.',
    `filing_period_start_date` DATE COMMENT 'The start date of the reporting period covered by this regulatory filing. For annual SEC reserves disclosures, this is the fiscal year start. For quarterly EPA reports, this is the quarter start date. Essential for compliance calendar management and period-over-period regulatory reporting.',
    `filing_status` STRING COMMENT 'Current lifecycle state of the regulatory filing submission. Tracks progression from internal draft through submission to final regulatory authority disposition. Serves as the LIFECYCLE_STATUS for this transaction. [ENUM-REF-CANDIDATE: draft|submitted|acknowledged|accepted|rejected|withdrawn|under_review|superseded — promote to reference product if additional states are needed]. Valid values are `draft|submitted|acknowledged|accepted|rejected|withdrawn`',
    `filing_type` STRING COMMENT 'Classification of the regulatory filing by its primary purpose and reporting category. Serves as the CLASSIFICATION_OR_TYPE for this transaction. Examples include annual reserves disclosure (SEC 10-K/20-F), quarterly environmental report (EPA), offshore incident report (BSEE), pipeline tariff filing (FERC), safety report (PHMSA 49 CFR 191/195), offshore permit (BOEM), OPEC quota compliance. [ENUM-REF-CANDIDATE: annual|quarterly|monthly|incident|permit|tariff|quota|safety|emergency|amendment|withdrawal — promote to reference product]',
    `ghg_emissions_scope` STRING COMMENT 'For environmental and GHG-related regulatory filings, identifies the GHG Protocol emissions scope covered: Scope 1 (direct emissions from owned/controlled sources), Scope 2 (indirect emissions from purchased energy), Scope 3 (all other indirect emissions in the value chain). Null or not_applicable for non-environmental filings.. Valid values are `scope_1|scope_2|scope_3|not_applicable`',
    `is_amendment` BOOLEAN COMMENT 'Indicates whether this filing is an amendment to a previously submitted regulatory filing. True if this is an amended submission (e.g., SEC 10-K/A, BSEE amended production report); False for original submissions. Used to distinguish original filings from corrective amendments in compliance reporting.',
    `jurisdiction` STRING COMMENT 'The geographic or political jurisdiction under which this regulatory filing is made (e.g., USA, GBR, NGA, SAU, or a US state code such as TX, LA, AK). Supports multi-national and multi-state compliance portfolio management for an international oil and gas operator.',
    `opec_quota_reference` STRING COMMENT 'The OPEC production quota reference or allocation identifier applicable to this filing, used specifically for OPEC quota compliance reports submitted by NOC (National Oil Company) entities. Tracks the production quota period, allocated volume, and compliance status against OPEC ministerial decisions.',
    `penalty_amount` DECIMAL(18,2) COMMENT 'The monetary penalty or fine assessed by the regulatory authority in connection with this filing or associated violation, expressed in the filing_fee_currency. Applicable for enforcement actions, late filings, or non-compliance findings. Zero or null for filings with no associated penalty.',
    `psa_reference` STRING COMMENT 'Reference to the Production Sharing Agreement (PSA) or Joint Operating Agreement (JOA) under which this regulatory filing is made, applicable for international upstream filings where the company operates under a host government PSA. Links the filing to the relevant contractual framework.',
    `regulatory_program_code` STRING COMMENT 'The specific regulatory program, rule, or regulation code under which this filing is made (e.g., 10-K for SEC annual report, 20-F for foreign private issuer, Form 2 for PHMSA gas distribution, Form 7000-1 for BSEE production, SPCC for EPA spill prevention, Form 501-G for FERC). Enables precise regulatory program tracking.',
    `rejection_reason` STRING COMMENT 'The reason provided by the regulatory authority for rejecting or returning this filing, where filing_status is rejected. Captures the authoritys stated deficiency or non-compliance finding to support corrective action and resubmission. Null for accepted or pending filings.',
    `reserves_category` STRING COMMENT 'The SPE Petroleum Resources Management System (PRMS) reserves classification category applicable to this filing, used specifically for SEC reserves disclosure filings (10-K/20-F). Values: 1P (Proved), 2P (Proved plus Probable), 3P (Proved plus Probable plus Possible), PDP (Proved Developed Producing), PUD (Proved Undeveloped), PDNP (Proved Developed Non-Producing). Null for non-reserves filings.. Valid values are `1P|2P|3P|PDP|PUD|PDNP`',
    `resubmission_due_date` DATE COMMENT 'The deadline by which a corrected or amended filing must be resubmitted to the regulatory authority following a rejection or deficiency notice. Null for filings that have not been rejected. Used for compliance calendar management and escalation tracking.',
    `sap_document_number` STRING COMMENT 'The SAP S/4HANA document number associated with this regulatory filing, particularly for filings that involve financial disclosures (SEC 10-K), cost recovery under joint venture agreements (JIB), or CAPEX/OPEX authorization (AFE). Enables cross-reference between the compliance record and the ERP financial system.',
    `sox_control_reference` STRING COMMENT 'The SOX internal control identifier or control framework reference associated with this regulatory filing, linking the filing to the companys SOX Section 302/404 internal control documentation. Supports SOX compliance audit trails for SEC-filed documents including 10-K reserves disclosures and financial statements.',
    `submission_channel` STRING COMMENT 'The method or channel through which the regulatory filing was submitted to the governing authority. Examples include electronic filing via SEC EDGAR, EPA CDX portal, BSEE TIMS, FERC eFiling, PHMSA portal, paper submission, or API-based automated submission.. Valid values are `electronic|paper|portal|api|email|courier`',
    `submission_timestamp` TIMESTAMP COMMENT 'The precise date and time when the regulatory filing was officially submitted to the governing authority. This is the principal real-world business event timestamp (BUSINESS_EVENT_TIMESTAMP) and is the legally binding submission time used for compliance deadline tracking and audit purposes.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this regulatory filing record was last modified in the compliance data system. Serves as the RECORD_AUDIT_UPDATED field for audit trail and data lineage purposes.',
    `violation_flag` BOOLEAN COMMENT 'Indicates whether this filing is associated with a regulatory violation, notice of violation (NOV), or enforcement action. True if the filing was triggered by or resulted in a violation finding. Supports violation tracking and enforcement action management within the compliance domain.',
    CONSTRAINT pk_regulatory_filing PRIMARY KEY(`regulatory_filing_id`)
) COMMENT 'Master record of all regulatory submissions made to governing bodies including SEC reserves disclosures (10-K/20-F proved reserves), EPA environmental filings, BSEE offshore safety reports, FERC pipeline tariff filings, PHMSA safety reports (49 CFR 191/195), BOEM offshore permits, OPEC quota compliance reports, and state commission filings. Tracks filing type, regulatory authority, submission date, filing period, status, official acknowledgment references, submission channel, and document versioning. Serves as the single audit trail for all outbound regulatory communications.';

CREATE OR REPLACE TABLE `oil_gas_ecm`.`compliance`.`permit` (
    `permit_id` BIGINT COMMENT 'Unique system-generated identifier for each permit record in the master permit register.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Permit applications frequently prepared by specialized environmental/regulatory consulting vendors in oil-and-gas operations. Real business process: permit application services procurement. Tracks whi',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Permit fees, bonds, and renewal costs are allocated to facility or project cost centers for operational budgeting, LOE tracking, and joint venture billing. Essential for matching permit_fee_amount and',
    `counterparty_id` BIGINT COMMENT 'Foreign key linking to customer.customer_counterparty. Business justification: Counterparties hold permits as operators or working interest owners. Real process: tracking permit ownership by counterparty for joint venture operations, operator changes, and determining which count',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Permits (drilling, environmental, operating) are issued to specific legal entities tracked as accounts. Real process: permit holder tracking for compliance verification, audit trails, and determining ',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Permits govern specific profit-generating operations (fields, facilities) and must be allocated to profit centers for segment P&L tracking, reserves attribution, and financial statement segment report',
    `quality_spec_id` BIGINT COMMENT 'Foreign key linking to product.product_quality_spec. Business justification: Air permits specify fuel quality limits (sulfur content, RVP) that must match product specifications. Required for demonstrating permit compliance during inspections and for opacity/emissions calculat',
    `regulatory_authority_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_authority. Business justification: A permit is issued by a regulatory authority (e.g., BOEM, EPA, state agency). The permit table has issuing_authority as a STRING which is denormalized. Adding regulatory_authority_id FK to the master ',
    `application_date` DATE COMMENT 'Date on which the company submitted the permit application to the issuing regulatory authority. Used to track regulatory processing timelines and support audit trails for compliance submissions.',
    `approval_date` DATE COMMENT 'Date on which the regulatory authority formally approved and issued the permit. Distinct from the effective date; used to measure regulatory processing time and support compliance audit trails.',
    `authorized_activity` STRING COMMENT 'Specific operational activity or activities authorized under this permit (e.g., exploratory drilling, production operations, crude oil discharge, natural gas flaring, pipeline construction, water injection). Derived from the permit conditions and used for operational compliance verification.',
    `block_number` STRING COMMENT 'Outer Continental Shelf (OCS) block number for offshore permits issued by BOEM or BSEE. Identifies the specific OCS block on which the permitted activity is authorized. Used for offshore regulatory reporting and geographic tracking.',
    `bond_amount` DECIMAL(18,2) COMMENT 'Financial assurance bond amount required by the issuing authority as a condition of the permit (e.g., BOEM decommissioning bond, BSEE well bond, state reclamation bond). Expressed in USD. Used for financial liability tracking and regulatory compliance.',
    `bond_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the permit bond amount (e.g., USD). Required for international permit portfolio management where bonds may be denominated in local currencies.. Valid values are `^[A-Z]{3}$`',
    `conditions_summary` STRING COMMENT 'Summary of key conditions, restrictions, and requirements attached to the permit by the issuing authority (e.g., emission limits, discharge limits, operational restrictions, monitoring requirements, reporting obligations). Full conditions are maintained in the permit document repository.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code for the country in which the permitted activity is located (e.g., USA, GBR, NOR). Supports international permit portfolio management for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this permit record was first created in the system. Supports audit trail requirements, SOX internal controls, and data lineage tracking in the compliance domain.',
    `document_reference` STRING COMMENT 'Reference identifier or URL to the official permit document stored in the companys document management system. Provides traceability to the original permit instrument, amendments, and supporting documentation for audit and compliance purposes.',
    `effective_date` DATE COMMENT 'Date on which the permit becomes legally effective and operations authorized by the permit may commence. This is the binding start date for compliance purposes and is distinct from the application date or approval date.',
    `emission_limit_unit` STRING COMMENT 'Unit of measure for the emission or discharge limit specified in the permit (e.g., tons per year, kg per day, lb per hour, MCFD, BOPD). Required for accurate compliance monitoring against permit thresholds.. Valid values are `tons_per_year|kg_per_day|lb_per_hour|mcfd|bopd`',
    `emission_limit_value` DECIMAL(18,2) COMMENT 'Quantitative emission limit authorized under the permit (e.g., tons per year of NOx, SO2, VOC, GHG). Applicable for EPA air emission permits (Title V, PSD, NSR). Used for environmental compliance monitoring and ESG reporting.',
    `expiration_date` DATE COMMENT 'Date on which the permit expires and authorized operations must cease unless renewed. Drives the compliance calendar for renewal tracking and regulatory deadline management. Null for permits with no fixed expiration.',
    `fee_amount` DECIMAL(18,2) COMMENT 'Fee paid to the issuing regulatory authority for the permit application, issuance, or renewal. Expressed in the bond currency. Used for CAPEX/OPEX tracking and regulatory cost management.',
    `geographic_area` STRING COMMENT 'Geographic area or region covered by the permit (e.g., OCS Gulf of Mexico, OCS Pacific, Permian Basin, Eagle Ford Shale, North Slope Alaska). Used for geographic compliance segmentation and BOEM/BSEE offshore area reporting.',
    `hse_classification` STRING COMMENT 'HSE risk classification of the permit based on the nature and severity of the authorized activity and associated environmental or safety risks. Critical permits (e.g., offshore drilling, H2S operations) require heightened monitoring and compliance controls per OSHA and EPA standards.. Valid values are `critical|major|minor|administrative`',
    `is_reportable_to_sec` BOOLEAN COMMENT 'Indicates whether this permit or its status (e.g., revocation, material violation) must be disclosed in SEC filings under reserves disclosure or material event reporting requirements. Supports SOX compliance and SEC reporting obligations.',
    `is_transferable` BOOLEAN COMMENT 'Indicates whether the permit can be transferred to another operator or entity (True) or is non-transferable (False). Relevant for merger, acquisition, and asset divestiture transactions where permit transfer approvals are required from the issuing authority.',
    `issuing_jurisdiction` STRING COMMENT 'Jurisdiction under which the permit was issued, including federal, state, or local designation and the specific state or offshore region (e.g., Federal-OCS Gulf of Mexico, Texas, Louisiana, Alaska). Supports multi-jurisdictional compliance management.',
    `jurisdiction_level` STRING COMMENT 'Level of government jurisdiction under which the permit was granted. Distinguishes between federal (BOEM, BSEE, EPA, PHMSA, FERC), state, local, tribal, or international regulatory authority for compliance segmentation and reporting.. Valid values are `federal|state|local|tribal|international`',
    `last_inspection_date` DATE COMMENT 'Date of the most recent regulatory inspection or audit conducted by the issuing authority related to this permit. Used to track inspection frequency, compliance history, and preparation for upcoming inspections.',
    `lease_number` STRING COMMENT 'Lease or land parcel number associated with the permitted activity. Links the permit to the land and lease management system (Quorum Land System) for integrated land, lease, and compliance tracking. Applicable for onshore and offshore lease-based permits.',
    `next_inspection_date` DATE COMMENT 'Date of the next scheduled regulatory inspection or compliance audit for this permit. Drives compliance calendar planning and preparation activities. May be set by the regulatory authority or estimated based on inspection frequency requirements.',
    `permit_description` STRING COMMENT 'Detailed narrative description of the activities, operations, or discharges authorized by the permit. Captures the scope of authorization including geographic boundaries, operational limits, and specific activities covered.',
    `permit_number` STRING COMMENT 'Official permit number assigned by the issuing regulatory authority (e.g., BOEM permit number, EPA permit number, BSEE well permit number). This is the externally-known identifier used in all regulatory correspondence and submissions.',
    `permit_status` STRING COMMENT 'Current lifecycle status of the permit. Tracks the permit from initial application through approval, active operations, suspension, expiration, or revocation. Critical for compliance calendar management and regulatory reporting. [ENUM-REF-CANDIDATE: applied|approved|active|suspended|expired|revoked|withdrawn — 7 candidates stripped; promote to reference product]',
    `permit_type` STRING COMMENT 'Classification of the permit by regulatory category. Covers BOEM offshore drilling permits, EPA air and water discharge permits, BSEE well permits, state environmental permits, and pipeline right-of-way permits. [ENUM-REF-CANDIDATE: drilling|environmental|pipeline_row|air_emission|water_discharge|offshore_operations|land_use|other — promote to reference product]',
    `regulatory_contact_name` STRING COMMENT 'Name of the primary contact person at the issuing regulatory authority responsible for this permit. Used for regulatory correspondence, permit inquiries, and compliance communications.',
    `regulatory_contact_phone` STRING COMMENT 'Phone number of the primary contact person at the issuing regulatory authority. Used for direct regulatory communications and permit-related inquiries.',
    `renewal_due_date` DATE COMMENT 'Date by which the permit renewal application must be submitted to the issuing authority to maintain continuous authorization. Typically set ahead of the expiration date per regulatory requirements. Drives compliance calendar alerts and renewal workflow initiation.',
    `renewal_status` STRING COMMENT 'Current status of the permit renewal process. Tracks whether a renewal is not required (e.g., one-time permits), pending initiation, submitted to the authority, approved, or denied. Supports proactive compliance management and regulatory deadline tracking.. Valid values are `not_required|pending|submitted|approved|denied`',
    `responsible_business_unit` STRING COMMENT 'Name of the internal business unit, division, or operating company responsible for maintaining compliance with this permit (e.g., Gulf of Mexico Offshore Operations, Permian Basin E&P, Refining and Marketing). Used for organizational accountability and compliance reporting.',
    `revocation_date` DATE COMMENT 'Date on which the permit was formally revoked by the issuing regulatory authority. Populated only when permit_status is revoked. Critical for violation tracking, regulatory reporting, and HSE compliance records.',
    `state_code` STRING COMMENT 'Two-letter US state code for the state in which the permitted activity is located (e.g., TX, LA, AK, CA). Used for state-level regulatory compliance tracking and multi-state permit portfolio management. Null for federal offshore permits.. Valid values are `^[A-Z]{2}$`',
    `subtype` STRING COMMENT 'Further classification within the permit type (e.g., for drilling: exploratory, development, workover; for environmental: NPDES, Title V air, stormwater; for pipeline: federal ROW, state ROW). Provides granular categorization for compliance tracking and reporting.',
    `suspension_date` DATE COMMENT 'Date on which the permit was suspended by the issuing authority or voluntarily by the company. Populated only when permit_status is suspended. Used for compliance incident tracking and regulatory reporting.',
    `title` STRING COMMENT 'Official descriptive title or name of the permit as assigned by the issuing authority (e.g., Application for Permit to Drill, Title V Operating Permit, NPDES General Permit for Stormwater Discharges). Provides human-readable identification for the permit register.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this permit record was most recently updated. Supports audit trail requirements, change tracking, and SOX internal controls for the compliance domain.',
    `violation_count` STRING COMMENT 'Total number of regulatory violations or notices of non-compliance recorded against this permit since issuance. Used for compliance risk scoring, regulatory relationship management, and ESG reporting. Incremented when violations are logged in the violation tracking system.',
    CONSTRAINT pk_permit PRIMARY KEY(`permit_id`)
) COMMENT 'Master register of all permits held or applied for by the company including BOEM offshore drilling permits, EPA air and water discharge permits, BSEE well permits, state environmental permits, and pipeline right-of-way permits. Tracks permit number, issuing authority, permit type, facility or asset covered, effective date, expiration date, renewal status, and associated conditions.';

CREATE OR REPLACE TABLE `oil_gas_ecm`.`compliance`.`operating_license` (
    `operating_license_id` BIGINT COMMENT 'Unique surrogate identifier for each operating license record in the Oil Gas enterprise data platform. Primary key for the operating_license data product. Role: MASTER_AGREEMENT.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: License annual fees and environmental bonds are charged to cost centers for production cost tracking and working interest allocation. Required for matching annual_fee_amount and environmental_bond_amo',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Operating licenses (exploration, production rights, PSA contracts) are granted to legal entities tracked as accounts. Real process: license holder tracking for production entitlements, royalty calcula',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Operating licenses govern profit-generating assets and operations; profit center linkage is essential for segment reporting, reserves attribution by segment, working interest tracking, and financial s',
    `regulatory_authority_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_authority. Business justification: An operating license is issued by a specific regulatory authority (e.g., BOEM issues offshore operating licenses, state commissions issue onshore operating licenses). The operating_license table has i',
    `annual_fee_amount` DECIMAL(18,2) COMMENT 'Annual fee payable to the issuing authority for maintaining the operating license in force. Recorded in the currency specified by currency_code. Tracked as OPEX (Operating Expenditure) in SAP S/4HANA CO module.',
    `api_operator_number` STRING COMMENT 'Five-digit American Petroleum Institute (API) assigned operator number uniquely identifying the operating company in federal and state regulatory databases. Required for BSEE, BOEM, and state oil and gas commission filings.. Valid values are `^[0-9]{5}$`',
    `area_gross_acres` DECIMAL(18,2) COMMENT 'Total gross surface area covered by the operating license measured in acres. Used for land and lease management, royalty calculations, and regulatory area reporting. Aligns with Quorum Land System acreage tracking.',
    `authorized_operations` STRING COMMENT 'Detailed description of the specific oil and gas operations authorized under this license (e.g., exploratory drilling, crude oil production, natural gas processing, pipeline transportation, LNG liquefaction and storage, refinery operations). Defines the operational scope boundary.',
    `commodity_type` STRING COMMENT 'Primary hydrocarbon commodity or product category covered by the operating license. Distinguishes licenses for crude oil (BOPD), natural gas (MCFD/MMCFD), NGL (Natural Gas Liquids), LPG (Liquefied Petroleum Gas), LNG (Liquefied Natural Gas), refined products, or petrochemicals. [ENUM-REF-CANDIDATE: crude_oil|natural_gas|ngl|lpg|lng|refined_products|petrochemicals|multiple — 8 candidates stripped; promote to reference product]',
    `conditions_summary` STRING COMMENT 'Summary of key conditions, stipulations, and special requirements attached to the operating license by the issuing authority (e.g., environmental mitigation measures, production rate limits, HSE reporting obligations, decommissioning bonds). Supports compliance obligation management.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this operating license record was first created in the enterprise data platform. RECORD_AUDIT_CREATED for this MASTER_AGREEMENT. Supports SOX audit trail and data lineage requirements. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for all monetary amounts on this license record (e.g., USD, GBP, EUR, SAR). Ensures consistent financial reporting across multi-national operations.. Valid values are `^[A-Z]{3}$`',
    `decommissioning_obligation` BOOLEAN COMMENT 'Indicates whether this operating license carries a decommissioning obligation requiring the licensee to plug and abandon (P&A) wells and remove facilities upon license expiry or cessation of production. Triggers asset retirement obligation (ARO) accounting under IFRS/GAAP.',
    `effective_date` DATE COMMENT 'Date on which the operating license becomes legally binding and operations may commence under its authority. EFFECTIVE_FROM for this MASTER_AGREEMENT. Aligns with the commencement date recorded in the licensing authoritys register.',
    `environmental_bond_amount` DECIMAL(18,2) COMMENT 'Dollar amount of the environmental surety bond or financial assurance required by the issuing authority as a condition of the operating license. Covers potential decommissioning, well P&A (Plug and Abandonment), and environmental remediation costs.',
    `expiry_date` DATE COMMENT 'Date on which the operating license ceases to be valid unless renewed or extended. EFFECTIVE_UNTIL for this MASTER_AGREEMENT. Nullable for perpetual or open-ended licenses. Critical for compliance calendar management and renewal obligation tracking.',
    `ghg_reporting_required` BOOLEAN COMMENT 'Indicates whether the operating license requires mandatory Greenhouse Gas (GHG) emissions reporting to the EPA or other environmental authority under the license conditions. Supports ESG reporting and EPA Mandatory Reporting Rule compliance.',
    `hse_classification` STRING COMMENT 'Health Safety and Environment (HSE) risk classification assigned to the operating license based on the nature and scale of authorized operations. High-risk licenses (e.g., deepwater drilling, H2S-bearing formations, NORM-handling) require enhanced HSE compliance monitoring in Enablon.. Valid values are `high_risk|medium_risk|low_risk`',
    `joa_reference` STRING COMMENT 'Reference number or identifier of the Joint Operating Agreement (JOA) associated with this operating license when the license is held jointly with co-venturers. Links to the governing JOA document for joint interest billing and partner obligations under SAP Joint Venture Accounting.',
    `jurisdiction_country` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code of the jurisdiction under which the license is issued and enforced (e.g., USA, GBR, NOR, SAU). Supports multi-national regulatory compliance management.. Valid values are `^[A-Z]{3}$`',
    `jurisdiction_state_province` STRING COMMENT 'State, province, or sub-national jurisdiction in which the license is issued and operative (e.g., Texas, Louisiana, Alberta, North Sea OCS). Required for state-level regulatory compliance tracking and reporting to state oil and gas commissions.',
    `last_renewal_date` DATE COMMENT 'Date on which the most recent renewal of this operating license was granted by the issuing authority. Establishes the current license term start for renewal cycle tracking.',
    `ldar_required` BOOLEAN COMMENT 'Indicates whether the operating license mandates a Leak Detection and Repair (LDAR) program as a condition of authorization. LDAR programs are required under EPA regulations for facilities emitting volatile organic compounds (VOCs) and hazardous air pollutants.',
    `license_category` STRING COMMENT 'Categorical classification of the license by the level of government authority that issued it. Federal licenses are issued by agencies such as BSEE, BOEM, FERC, or EPA. State licenses are issued by state oil and gas commissions. International licenses are issued by foreign national authorities or NOCs.. Valid values are `federal|state|local|international|tribal`',
    `license_class` STRING COMMENT 'Operational environment classification of the license. Onshore covers land-based E&P operations. Offshore covers continental shelf operations. Deepwater and ultra-deepwater apply to BSEE/BOEM regulated OCS operations. Pipeline covers FERC/PHMSA regulated transportation. Facility covers refineries and processing plants.. Valid values are `onshore|offshore|deepwater|ultra_deepwater|pipeline|facility`',
    `license_name` STRING COMMENT 'Human-readable descriptive name or title of the operating license as assigned by the licensing authority or internally designated (e.g., Gulf of Mexico OCS Lease G-12345, Texas Railroad Commission Operator Permit). Serves as the IDENTITY_LABEL for this agreement.',
    `license_number` STRING COMMENT 'Externally-known, officially-assigned license or authorization number issued by the licensing authority (e.g., BSEE lease number, EPA permit ID, FERC certificate number, BOEM OCS lease number). This is the BUSINESS_IDENTIFIER used in all regulatory correspondence and submissions.',
    `license_status` STRING COMMENT 'Current lifecycle state of the operating license. LIFECYCLE_STATUS for this MASTER_AGREEMENT. Active indicates the license is in force; suspended indicates temporary halt by authority; expired indicates past effective-until date without renewal; pending indicates awaiting authority approval; revoked indicates permanently cancelled; under_renewal indicates renewal application submitted.. Valid values are `active|suspended|expired|pending|revoked|under_renewal`',
    `license_type` STRING COMMENT 'Classification of the operating license by the category of operations it authorizes. CLASSIFICATION_OR_TYPE for this MASTER_AGREEMENT. [ENUM-REF-CANDIDATE: exploration_license|production_license|pipeline_operating_certificate|refinery_operating_license|lng_facility_license|environmental_permit|drilling_permit|storage_license|terminal_operating_license|ngl_processing_license — promote to reference product]. Valid values are `exploration_license|production_license|pipeline_operating_certificate|refinery_operating_license|lng_facility_license|environmental_permit`',
    `licensed_area_description` STRING COMMENT 'Textual description of the geographic area, block, tract, or facility covered by the operating license (e.g., OCS Block designation, lease tract description, pipeline corridor, refinery site address). Defines the spatial scope of authorized operations.',
    `net_revenue_interest_pct` DECIMAL(18,2) COMMENT 'Net Revenue Interest (NRI) percentage representing the companys share of production revenue after deducting royalties and overriding royalty interests (ORRI). Expressed as a decimal percentage. Used for revenue allocation and SEC reserves disclosure.',
    `production_capacity_boe` DECIMAL(18,2) COMMENT 'Maximum authorized production or throughput capacity expressed in Barrels of Oil Equivalent (BOE) per day as stipulated in the license conditions. Represents the principal quantitative constraint of the license. Used for OPEC quota compliance and SEC reserves disclosure.',
    `psa_indicator` BOOLEAN COMMENT 'Indicates whether this operating license is governed by a Production Sharing Agreement (PSA) with a host government or National Oil Company (NOC). When True, PSA fiscal terms and cost recovery provisions apply to production accounting and revenue recognition.',
    `regulatory_reference_number` STRING COMMENT 'Additional regulatory docket, case, or reference number assigned by the issuing authority for tracking the license application and correspondence (e.g., FERC docket number, EPA permit tracking number, BSEE incident of non-compliance number). Supplements the primary license_number.',
    `renewal_application_date` DATE COMMENT 'Date on which the renewal application was submitted to the issuing authority. Used to confirm timely submission relative to the renewal lead time requirement and to track the renewal process lifecycle.',
    `renewal_lead_days` STRING COMMENT 'Number of calendar days prior to the expiry date by which the renewal application must be submitted to the issuing authority to maintain continuous operational authorization. Drives compliance calendar alerts and workflow triggers in Enablon HSE Management.',
    `renewal_required` BOOLEAN COMMENT 'Indicates whether this operating license requires periodic renewal before the expiry date. When True, renewal obligations must be tracked in the compliance calendar and renewal applications submitted to the issuing authority within the required lead time.',
    `royalty_rate_pct` DECIMAL(18,2) COMMENT 'Royalty rate percentage payable to the mineral rights owner or government authority as a condition of the operating license. Expressed as a decimal percentage (e.g., 12.5000 for 12.5%). Impacts LOE (Lease Operating Expense) and net revenue calculations.',
    `source_system_code` STRING COMMENT 'Identifier of the operational system of record from which this license record originates (e.g., Enablon HSE Management permit register, Quorum Land System lease record, SAP S/4HANA compliance module). Supports data lineage and audit trail requirements.',
    `suspension_date` DATE COMMENT 'Date on which the operating license was suspended by the issuing authority. Populated only when license_status is suspended. Triggers operational halt and compliance remediation workflow.',
    `suspension_reason` STRING COMMENT 'Textual description of the reason for license suspension as communicated by the issuing authority. Documents the compliance violation, safety incident, or administrative cause triggering the suspension. Supports HSE incident tracking in Enablon.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this operating license record was most recently modified in the enterprise data platform. Supports change tracking, audit trail, and SOX internal controls. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `working_interest_pct` DECIMAL(18,2) COMMENT 'Companys Working Interest (WI) percentage in the licensed area, representing the proportionate share of costs and production entitlement. Expressed as a decimal percentage (e.g., 65.0000 for 65%). Critical for Joint Interest Billing (JIB) and COPAS accounting.',
    CONSTRAINT pk_operating_license PRIMARY KEY(`operating_license_id`)
) COMMENT 'Master record of all operating licenses and authorizations required to conduct oil and gas operations including exploration licenses, production licenses, refinery operating licenses, pipeline operating certificates, and LNG facility licenses. Tracks license number, licensing authority, jurisdiction, scope of operations authorized, conditions, and renewal obligations.';

CREATE OR REPLACE TABLE `oil_gas_ecm`.`compliance`.`obligation` (
    `obligation_id` BIGINT COMMENT 'Unique system-generated identifier for each regulatory compliance obligation record in the master catalog.',
    `contract_id` BIGINT COMMENT 'Foreign key linking to procurement.contract. Business justification: Compliance obligations frequently arise from contractual commitments in PSAs, JOAs, and service agreements (e.g., HSE reporting, local content, decommissioning). Linking obligation to contract enables',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Compliance obligations have estimated_compliance_cost tracked by cost center for budget planning and variance analysis. Reusing existing sap_cost_center column (unlinked) would be ideal, but its a pl',
    `petroleum_product_id` BIGINT COMMENT 'Foreign key linking to product.petroleum_product. Business justification: Product-specific compliance obligations include RFS2 renewable fuel mandates, state fuel specification requirements (CARB diesel, RFG programs), product registration renewals, and fuel quality monitor',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Compliance obligations are tied to specific operating segments/profit centers for management accountability, segment reporting, and estimated compliance cost allocation. Essential for segment P&L fore',
    `regulatory_authority_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_authority. Business justification: A compliance obligation is mandated by a specific regulatory authority (e.g., EPA, BSEE, FERC, PHMSA). The obligation table has regulatory_body as a STRING which is denormalized. Adding regulatory_aut',
    `advance_notice_days` STRING COMMENT 'Number of days before the due date that an internal compliance alert or reminder should be triggered to the obligation owner and responsible department. Supports proactive compliance management.',
    `compliance_frequency` STRING COMMENT 'Recurrence frequency at which the compliance action must be performed: one_time, daily, weekly, monthly, quarterly, semi_annual, annual, biennial, triennial, or event_driven (triggered by a specific operational event). Drives the compliance calendar. [ENUM-REF-CANDIDATE: one_time|daily|weekly|monthly|quarterly|semi_annual|annual|biennial|triennial|event_driven — promote to reference product]',
    `compliance_status` STRING COMMENT 'Current compliance lifecycle state of the obligation: compliant (action completed on time), non_compliant (action missed or deficient), pending (action in progress), overdue (past due date without completion), waived (formally exempted by regulator), or under_review (regulator or internal review in progress).. Valid values are `compliant|non_compliant|pending|overdue|waived|under_review`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the country in which this obligation applies (e.g., USA, GBR, NOR, SAU). Supports international operations and multi-country compliance tracking.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this obligation record was first created in the compliance master catalog. Supports audit trail and data lineage requirements.',
    `data_domain` STRING COMMENT 'Primary data domain to which this obligation belongs, aligning with the enterprise data governance taxonomy. Supports domain-based compliance reporting and ownership assignment. [ENUM-REF-CANDIDATE: exploration|drilling|production|reservoir|refining|petrochemicals|supply_chain|marketing_sales|land_lease|joint_venture|hse|workforce|finance|asset_management|contracts_procurement|regulatory_compliance|transportation_logistics — promote to reference product]',
    `effective_from_date` DATE COMMENT 'Date on which this regulatory obligation became or becomes binding on the company. Marks the start of the compliance obligation period.',
    `effective_until_date` DATE COMMENT 'Date on which this regulatory obligation expires or is no longer binding. Null for open-ended or perpetual obligations. Supports permit expiry tracking and renewal workflows.',
    `enablon_obligation_ref` STRING COMMENT 'Reference identifier of this obligation record in the Enablon HSE Management system, which is the operational system of record for HSE compliance, permit-to-work, and environmental compliance tracking.',
    `esg_reporting_flag` BOOLEAN COMMENT 'Indicates whether this obligation contributes to Environmental, Social, and Governance (ESG) reporting disclosures (True), including GHG emissions, LDAR programs, NORM management, or social compliance.',
    `estimated_compliance_cost` DECIMAL(18,2) COMMENT 'Estimated annual OPEX cost in the penalty currency to fulfill this obligation, including labor, monitoring, reporting, and third-party services. Used for compliance budget planning and CAPEX/OPEX allocation.',
    `ghg_emission_scope` STRING COMMENT 'For GHG and environmental reporting obligations, the GHG Protocol emission scope: scope_1 (direct emissions from owned/controlled sources), scope_2 (indirect from purchased energy), scope_3 (value chain indirect), or not_applicable for non-GHG obligations.. Valid values are `scope_1|scope_2|scope_3|not_applicable`',
    `is_material` BOOLEAN COMMENT 'Indicates whether this obligation is considered material for SEC financial disclosure, SOX internal controls, or ESG reporting purposes (True) or is non-material (False).',
    `is_recurring` BOOLEAN COMMENT 'Indicates whether this obligation recurs on a defined schedule (True) or is a one-time requirement (False). Drives automated compliance calendar generation.',
    `jurisdiction` STRING COMMENT 'Geographic or legal jurisdiction in which this obligation applies (e.g., Federal, Texas, Gulf of Mexico OCS, Alaska North Slope, International). Supports multi-jurisdictional compliance management.',
    `last_audit_date` DATE COMMENT 'Date of the most recent internal or external audit that reviewed compliance with this obligation. Supports audit trail requirements and SOX 404 documentation.',
    `last_audit_result` STRING COMMENT 'Outcome of the most recent audit of this obligation: satisfactory (fully compliant), minor_finding (low-risk gap), major_finding (significant gap requiring corrective action), critical_finding (immediate regulatory risk), or not_audited.. Valid values are `satisfactory|minor_finding|major_finding|critical_finding|not_audited`',
    `last_completed_date` DATE COMMENT 'Date on which the most recent compliance action for this obligation was completed and submitted. Used to calculate compliance history and next due date for recurring obligations.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this obligation record was most recently modified in the compliance master catalog. Supports change management, audit trail, and SOX internal controls documentation.',
    `max_penalty_amount` DECIMAL(18,2) COMMENT 'Maximum statutory monetary penalty per violation or per day of non-compliance as defined by the applicable regulation (in USD). Used for risk quantification and CAPEX/OPEX planning for compliance investments.',
    `next_due_date` DATE COMMENT 'The next calendar date by which the compliance action must be completed or submitted to the regulatory authority. Drives the compliance calendar and alert notifications.',
    `obligation_category` STRING COMMENT 'High-level business category grouping the obligation: environmental (EPA/GHG), safety (OSHA/BSEE/HSE), financial (SEC/SOX/COPAS), operational (FERC/PHMSA), land_lease (BOEM/Quorum), export_import, labor, tax, or esg (ESG reporting). [ENUM-REF-CANDIDATE: environmental|safety|financial|operational|land_lease|export_import|labor|tax|esg — promote to reference product]',
    `obligation_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the obligation across regulatory submissions, permit registers, and compliance calendars (e.g., EPA-00012345, BSEE-20240001).. Valid values are `^[A-Z]{2,6}-[0-9]{4,8}$`',
    `obligation_description` STRING COMMENT 'Detailed narrative describing the full scope of the regulatory compliance obligation, including what action must be taken, by whom, and under what conditions.',
    `obligation_type` STRING COMMENT 'Classification of the obligation by its nature: reporting (e.g., SEC reserves disclosure), permit (e.g., BOEM offshore permit), license (e.g., FERC gas pipeline license), inspection (e.g., BSEE facility inspection), certification (e.g., OSHA safety certification), consent_order, tariff_filing, audit, training, or monitoring. [ENUM-REF-CANDIDATE: reporting|permit|license|inspection|certification|consent_order|tariff_filing|audit|training|monitoring — promote to reference product]',
    `opec_quota_applicable` BOOLEAN COMMENT 'Indicates whether this obligation is related to OPEC production quota compliance (True), requiring production volume monitoring and reporting to the national oil company or government authority.',
    `penalty_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the maximum penalty amount (e.g., USD, GBP, EUR). Supports multi-currency international operations.. Valid values are `^[A-Z]{3}$`',
    `penalty_risk_level` STRING COMMENT 'Assessed risk level of non-compliance based on potential regulatory penalties, operational impact, and reputational consequences: critical (facility shutdown, criminal liability), high (major fines, license revocation), medium (civil penalties, corrective action orders), or low (minor administrative penalties).. Valid values are `critical|high|medium|low`',
    `prms_reserves_category` STRING COMMENT 'For SEC reserves disclosure obligations, the Petroleum Resources Management System (PRMS) reserves category to which this obligation applies: 1P (Proved), 2P (Proved plus Probable), 3P (Proved plus Probable plus Possible), PDP (Proved Developed Producing), PUD (Proved Undeveloped), or PDNP (Proved Developed Non-Producing). Null for non-reserves obligations.. Valid values are `1P|2P|3P|PDP|PUD|PDNP`',
    `regulation_citation` STRING COMMENT 'Specific legal or regulatory citation that creates this obligation (e.g., 40 CFR Part 98 Subpart W, 30 CFR Part 250.1920, 49 CFR Part 195.452, SEC Rule 4-10(a)). Used for audit trail and legal defensibility.',
    `reporting_form_number` STRING COMMENT 'Official form number or submission template identifier required by the regulatory authority for this obligation (e.g., EPA Form 7540-1, BSEE Form MMS-133, SEC Form 10-K, FERC Form 2). Supports submission workflow automation.',
    `responsible_business_unit` STRING COMMENT 'Name of the internal business unit or division accountable for fulfilling this obligation (e.g., Upstream E&P, Refining Operations, HSE Compliance, Finance and Reporting, Supply Chain). Aligns with SAP S/4HANA organizational hierarchy.',
    `responsible_department` STRING COMMENT 'Specific department within the responsible business unit that owns day-to-day compliance actions for this obligation (e.g., Environmental Affairs, Drilling Engineering, Regulatory Affairs, Legal).',
    `source_instrument_number` STRING COMMENT 'Official number or identifier of the permit, license, consent order, or regulation that is the source of this obligation (e.g., permit number, docket number, consent decree case number). Links to the permit register.',
    `source_instrument_type` STRING COMMENT 'Type of legal instrument from which this obligation is derived: federal_regulation, state_regulation, permit, license, consent_order, settlement_agreement, executive_order, or tariff. Determines the legal authority and enforcement mechanism. [ENUM-REF-CANDIDATE: federal_regulation|state_regulation|permit|license|consent_order|settlement_agreement|executive_order|tariff — 8 candidates stripped; promote to reference product]',
    `sox_control_flag` BOOLEAN COMMENT 'Indicates whether this obligation is linked to a Sarbanes-Oxley (SOX) internal control (True) and must be included in the annual SOX 302/404 certification process.',
    `submission_deadline_days` STRING COMMENT 'Number of calendar days after the trigger event or period end by which the compliance submission must be filed with the regulatory authority (e.g., 30 days after fiscal year end for SEC annual reserves disclosure).',
    `submission_method` STRING COMMENT 'Required method for submitting the compliance deliverable to the regulatory authority: electronic (e.g., EPA CDX, BSEE TIMS), paper, online_portal, email, or certified_mail.. Valid values are `electronic|paper|online_portal|email|certified_mail`',
    `title` STRING COMMENT 'Short, human-readable title of the regulatory obligation as referenced in the permit, regulation, or consent order (e.g., Annual GHG Emissions Report, BSEE SEMS Audit, PHMSA Pipeline Integrity Report).',
    `violation_count` STRING COMMENT 'Cumulative number of documented regulatory violations or notices of non-compliance issued against this obligation. Supports violation tracking, penalty risk assessment, and regulatory relationship management.',
    CONSTRAINT pk_obligation PRIMARY KEY(`obligation_id`)
) COMMENT 'Master catalog of all regulatory compliance obligations applicable to the company derived from federal and state regulations, permits, licenses, consent orders, and settlement agreements. Each obligation defines the regulatory requirement, applicable regulation citation, responsible business unit, frequency of compliance action, due date logic, consequence of non-compliance, and current compliance status. Serves as the authoritative register of what the company must do to remain compliant and the central hub linking permits, filings, violations, and calendar events.';

CREATE OR REPLACE TABLE `oil_gas_ecm`.`compliance`.`calendar` (
    `calendar_id` BIGINT COMMENT 'Unique surrogate identifier for each scheduled compliance calendar event. Primary key for the compliance calendar data product.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Compliance calendar events require cost center assignment for departmental accountability, budget tracking, and resource allocation planning. Real business process: compliance workload planning and de',
    `obligation_id` BIGINT COMMENT 'Reference to the parent regulatory compliance obligation that generated this calendar event. Links the scheduled action back to its governing obligation record.',
    `permit_id` BIGINT COMMENT 'Reference to the permit or license record associated with this calendar event, applicable for permit renewal deadlines, inspection due dates, and certification expirations.',
    `petroleum_product_id` BIGINT COMMENT 'Foreign key linking to product.petroleum_product. Business justification: Compliance calendars track product-specific deadlines: quarterly fuel quality reports by product grade, annual EPA product registrations, state fuel specification certifications, and seasonal fuel tra',
    `regulatory_authority_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_authority. Business justification: A compliance calendar event is associated with a specific regulatory authority (e.g., EPA filing deadline, FERC tariff submission, BSEE inspection schedule). The calendar table has regulatory_authorit',
    `business_unit` STRING COMMENT 'Name of the internal business unit or operating division responsible for fulfilling this compliance obligation (e.g., Upstream E&P, Refining, Petrochemicals, Midstream, Corporate). Supports organizational reporting and accountability assignment.',
    `certification_required` BOOLEAN COMMENT 'Indicates whether this compliance event requires an officer-level certification or attestation (e.g., SOX Section 302/404 CEO/CFO certification, SEC reserves certification by qualified petroleum engineer, BSEE SEMS audit certification).',
    `certifying_officer` STRING COMMENT 'Name or title of the officer or qualified professional responsible for certifying or attesting to the accuracy of the regulatory submission (e.g., CEO, CFO, Qualified Petroleum Engineer for SEC reserves). Applicable when certification_required is True.',
    `completion_date` DATE COMMENT 'Actual date on which the compliance action was completed, filed, or submitted. Null if not yet completed. Used to calculate on-time performance and support audit trail requirements.',
    `compliance_domain` STRING COMMENT 'High-level business domain classification for this compliance event, enabling domain-based filtering and reporting across the compliance calendar. [ENUM-REF-CANDIDATE: environmental|safety|financial|reserves|pipeline|offshore|export_control|labor|tax|hse|esg — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this compliance calendar event record was first created in the system. Supports audit trail requirements under SOX internal controls and data lineage tracking in the Databricks Silver Layer.',
    `days_overdue` STRING COMMENT 'Number of calendar days by which this compliance event has exceeded its regulatory due date without completion. Populated only when overdue_flag is True. Used for regulatory risk scoring and enforcement exposure assessment.',
    `due_date` DATE COMMENT 'The hard regulatory deadline by which the compliance action must be completed or submitted to the regulatory authority. May differ from scheduled_date when internal preparation time is factored in.',
    `escalation_contact` STRING COMMENT 'Name or identifier of the manager or senior officer to be notified when this compliance event becomes overdue or at risk. Supports the escalation threshold workflow for overdue items.',
    `escalation_threshold_days` STRING COMMENT 'Number of days before the due date at which an escalation notification is triggered if the compliance event has not been completed. Enables proactive overdue management and prevents regulatory violations.',
    `esg_category` STRING COMMENT 'ESG classification for this compliance event, indicating whether it relates to environmental (GHG emissions, LDAR, spill prevention), social (OSHA worker safety, SIMOPS), or governance (SOX, SEC disclosure, COPAS) obligations. Supports ESG reporting frameworks.. Valid values are `environmental|social|governance|none`',
    `event_reference_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to this compliance calendar event, used in regulatory submissions and internal tracking systems such as Enablon HSE Management.. Valid values are `^[A-Z]{2,6}-[0-9]{4}-[0-9]{4,8}$`',
    `event_status` STRING COMMENT 'Current lifecycle status of the compliance calendar event, tracking progression from scheduled through completion or escalation. Drives compliance dashboard reporting and overdue escalation workflows.. Valid values are `scheduled|in_progress|completed|overdue|waived|cancelled`',
    `event_type` STRING COMMENT 'Classification of the compliance calendar event indicating the nature of the required action. [ENUM-REF-CANDIDATE: filing_deadline|permit_renewal|inspection_due|certification_expiration|reporting_window|audit_scheduled|quota_submission|tariff_filing — promote to reference product]. Valid values are `filing_deadline|permit_renewal|inspection_due|certification_expiration|reporting_window|audit_scheduled`',
    `extended_due_date` DATE COMMENT 'Revised regulatory deadline date granted by the regulatory authority when an extension has been approved. Null when extension_granted is False. Supersedes due_date for compliance tracking purposes when populated.',
    `extension_granted` BOOLEAN COMMENT 'Indicates whether the regulatory authority has granted a formal extension of the filing or compliance deadline for this event. When True, the extended_due_date field captures the revised deadline.',
    `form_type` STRING COMMENT 'Official name or code of the regulatory form, report, or filing required for this compliance event (e.g., SEC Form 10-K, SEC Form 10-Q, EPA Form GHG, BSEE Form MMS-133, FERC Form 2, PHMSA Form 7100.1-1).',
    `ghg_related` BOOLEAN COMMENT 'Indicates whether this compliance event is related to greenhouse gas (GHG) emissions reporting, monitoring, or reduction obligations under EPA 40 CFR Part 98 or equivalent international regulations. Supports ESG and climate disclosure tracking.',
    `jurisdiction` STRING COMMENT 'Geographic or legal jurisdiction governing this compliance obligation, expressed as a 2-3 character ISO country or US state code (e.g., US, UK, NG, SA, TX, LA). Determines applicable regulatory framework and submission authority.. Valid values are `^[A-Z]{2,3}$`',
    `notes` STRING COMMENT 'Free-text field for compliance officers to record contextual information, regulatory correspondence references, internal review comments, or special instructions related to this compliance calendar event.',
    `overdue_flag` BOOLEAN COMMENT 'Indicates whether this compliance calendar event has passed its due date without completion. True when current date exceeds due_date and event_status is not completed, waived, or cancelled. Drives compliance risk dashboards.',
    `owner_department` STRING COMMENT 'Name of the department or functional group to which the assigned compliance owner belongs (e.g., HSE, Legal, Finance, Regulatory Affairs, Operations). Supports departmental compliance reporting.',
    `penalty_exposure_usd` DECIMAL(18,2) COMMENT 'Estimated maximum financial penalty in US dollars that could be assessed by the regulatory authority for non-compliance or late filing of this obligation. Used for compliance risk prioritization and CAPEX/OPEX planning.',
    `priority_level` STRING COMMENT 'Business-assigned priority level for this compliance event, reflecting regulatory risk, penalty exposure, and operational impact. Critical items include SEC reserves disclosures, BSEE offshore safety reports, and EPA major source permits.. Valid values are `critical|high|medium|low`',
    `recurrence_end_date` DATE COMMENT 'Date after which no further recurring compliance calendar events will be generated for this obligation. Null for open-ended recurring obligations. Used by the compliance calendar scheduling engine.',
    `recurrence_pattern` STRING COMMENT 'Frequency pattern defining how often this compliance obligation recurs and generates new calendar events (e.g., annual SEC 10-K filing, quarterly EPA emissions reports, monthly BSEE production reports, one-time permit application).. Valid values are `one_time|daily|weekly|monthly|quarterly|annual`',
    `regulatory_program` STRING COMMENT 'Specific regulatory program or rule set under which this compliance event is required (e.g., SEC Reserves Disclosure, EPA GHG Reporting, BSEE SEMS, PHMSA Integrity Management, FERC Gas Tariff, OPEC Quota Compliance, SOX Section 302/404).',
    `reporting_period_end` DATE COMMENT 'End date of the regulatory reporting period covered by this compliance event. Together with reporting_period_start, defines the data window for which the regulatory submission or action applies.',
    `reporting_period_start` DATE COMMENT 'Start date of the regulatory reporting period covered by this compliance event (e.g., beginning of the fiscal quarter for SEC filings, start of the calendar year for EPA GHG reports, beginning of the OPEC quota period).',
    `scheduled_date` DATE COMMENT 'The principal calendar date on which this compliance action is scheduled to occur or by which it must be completed. Serves as the primary deadline date for compliance tracking and escalation.',
    `source_system` STRING COMMENT 'Name of the operational system of record from which this compliance calendar event was originated or ingested (e.g., Enablon HSE Management for HSE compliance events, SAP S/4HANA for financial regulatory filings, Quorum for land and lease permit renewals).. Valid values are `Enablon|SAP_S4HANA|Quorum|Manual|SCADA|PI_System`',
    `submission_method` STRING COMMENT 'Method by which the regulatory filing or compliance action is submitted to the regulatory authority (e.g., electronic via SEC EDGAR, EPA CDX, BSEE eWell, FERC eFiling, or paper submission).. Valid values are `electronic|paper|portal|email|in_person`',
    `submission_reference` STRING COMMENT 'Confirmation number, accession number, or tracking reference assigned by the regulatory authority upon receipt of the submission (e.g., SEC EDGAR accession number, EPA CDX submission ID, BSEE confirmation number).',
    `submission_timestamp` TIMESTAMP COMMENT 'Precise date and time at which the regulatory filing, report, or submission was transmitted to the regulatory authority. Provides exact proof of timely submission for audit and enforcement purposes.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this compliance calendar event record. Tracks changes to scheduled dates, status updates, owner reassignments, and extension grants for audit trail purposes.',
    CONSTRAINT pk_calendar PRIMARY KEY(`calendar_id`)
) COMMENT 'Scheduled compliance events and regulatory deadlines derived from compliance obligations. Tracks each scheduled compliance action including filing deadlines, permit renewal dates, inspection due dates, certification expirations, and reporting windows. Includes assigned owner, regulatory authority, associated obligation, scheduled date, completion date, and escalation thresholds for overdue items.';

CREATE OR REPLACE TABLE `oil_gas_ecm`.`compliance`.`violation` (
    `violation_id` BIGINT COMMENT 'Unique system-generated identifier for each regulatory violation, notice of violation (NOV), or non-compliance finding record. Primary key for the violation data product.',
    `asset_facility_id` BIGINT COMMENT 'Identifier of the facility, asset, or operational site where the violation occurred or was identified (e.g., refinery, offshore platform, pipeline segment, well pad).',
    `asset_id` BIGINT COMMENT 'Identifier of the specific physical asset (equipment, pipeline, well, vessel) directly associated with the violation, as tracked in Maximo Asset Management.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Violations require cost center allocation for departmental accountability, budget impact tracking, and corrective action cost management beyond GL account. Essential for management reporting and depar',
    `equipment_id` BIGINT COMMENT 'Foreign key linking to asset.equipment. Business justification: Violations are issued against specific equipment (e.g., PRV failure NOV, compressor emission violation, pressure vessel overpressure). violation links to asset_facility but not equipment; equipment-le',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Violations trigger penalty accruals and reserves requiring GL account mapping for financial statement preparation, SEC disclosure, and SOX controls. Essential for posting penalty_amount to proper liab',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: A regulatory violation is a breach of a specific compliance obligation. Linking violation to obligation enables traceability from the violation back to the underlying regulatory requirement that was b',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: A violation is often tied to a specific permit condition (e.g., exceeding emission limits on an air permit, violating BOEM drilling permit conditions). The violation table has permit_number as a STRIN',
    `petroleum_product_id` BIGINT COMMENT 'Foreign key linking to product.petroleum_product. Business justification: Violations frequently cite specific petroleum products: off-specification fuel sales, unauthorized product marketing, mislabeled products, or contaminated product releases. Product identification is e',
    `pipeline_segment_id` BIGINT COMMENT 'Foreign key linking to asset.pipeline_segment. Business justification: PHMSA NOVs and state pipeline safety violations are issued against specific pipeline segments. violation links to asset_facility but not pipeline_segment; segment-level violation tracking is required ',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Violations impact specific operating segments and must be allocated to profit centers for segment performance measurement, P&L impact analysis, and management accountability. Essential for accurate se',
    `regulatory_authority_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_authority. Business justification: A violation is issued by a specific regulatory authority (e.g., EPA issues NOVs, BSEE issues offshore violations). The violation table has issuing_authority as a STRING which is denormalized. Adding r',
    `well_asset_id` BIGINT COMMENT 'Foreign key linking to asset.well_asset. Business justification: Violations (e.g., well integrity failures, H2S releases, spills) are issued against specific wells. violation links to asset_facility and asset but not well_asset; well-level violation tracking is req',
    `appeal_filed_date` DATE COMMENT 'Date the formal appeal was filed with the regulatory authority or administrative review body. Null if no appeal has been filed. Used to track appeal deadlines and statute of limitations.',
    `appeal_status` STRING COMMENT 'Status of any formal appeal filed against the violation finding or assessed penalty: not_appealed, appeal_filed (submitted to authority), appeal_pending (under review), appeal_granted (violation or penalty reduced/dismissed), appeal_denied, or appeal_withdrawn.. Valid values are `not_appealed|appeal_filed|appeal_pending|appeal_granted|appeal_denied|appeal_withdrawn`',
    `capa_completion_date` DATE COMMENT 'Actual date the CAPA plan was fully implemented and all corrective actions were completed. Null if CAPA is still in progress. Compared against capa_target_date to assess timeliness of corrective response.',
    `capa_description` STRING COMMENT 'Detailed description of the Corrective and Preventive Action (CAPA) plan developed to address the root cause of the violation and prevent recurrence. Includes specific corrective steps, process changes, and preventive measures.',
    `capa_effectiveness_review` STRING COMMENT 'Assessment of whether the implemented CAPA has been effective in preventing recurrence of the violation: not_started, in_progress (review underway), effective (no recurrence observed), partially_effective (improvement noted but not fully resolved), or ineffective (recurrence observed, additional action required).. Valid values are `not_started|in_progress|effective|partially_effective|ineffective`',
    `capa_responsible_party` STRING COMMENT 'Name or role of the individual or organizational unit accountable for implementing the CAPA plan (e.g., Operations Manager, HSE Director, Facility Superintendent). Supports accountability tracking and SOX control ownership.',
    `capa_target_date` DATE COMMENT 'Planned completion date for full implementation of the CAPA plan. Used to monitor corrective action progress against regulatory response deadlines and internal compliance milestones.',
    `capa_verification_method` STRING COMMENT 'Description of the method used to verify that the CAPA has been effectively implemented (e.g., regulatory inspection, internal audit, third-party verification, monitoring data review, management walkthrough). Required for regulatory closure documentation.',
    `closure_date` DATE COMMENT 'Date the violation was formally closed by the regulatory authority or verified as resolved through internal compliance review. Null if the violation remains open. Used for regulatory closure documentation and ESG reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the violation record was first created in the compliance management system (Enablon HSE Management or SAP S/4HANA). Supports audit trail, SOX internal controls, and data lineage tracking in the Databricks Silver Layer.',
    `discovery_date` DATE COMMENT 'Date the violation was first identified, whether through regulatory inspection, internal audit, self-disclosure, or monitoring system alert. Distinct from the date the NOV was formally issued. Critical for calculating response timelines and regulatory reporting deadlines.',
    `discovery_source` STRING COMMENT 'Source through which the violation was identified: regulatory_inspection (government inspector), internal_audit (company HSE or compliance audit), self_disclosure (voluntary company disclosure to regulator), monitoring_system (SCADA/PI System automated alert), third_party_audit (independent auditor), or employee_report (internal report or near-miss notification).. Valid values are `regulatory_inspection|internal_audit|self_disclosure|monitoring_system|third_party_audit|employee_report`',
    `end_date` DATE COMMENT 'Date the non-compliant condition or activity ceased, either through corrective action or regulatory determination. Null if the violation is ongoing. Used with violation_start_date to calculate total duration of non-compliance.',
    `ghg_related` BOOLEAN COMMENT 'Indicates whether the violation is related to Greenhouse Gas (GHG) emissions reporting, monitoring, or control requirements. True if GHG-related; False otherwise. Supports ESG reporting, EPA GHG Reporting Program compliance, and carbon disclosure obligations.',
    `internal_reference_number` STRING COMMENT 'Company-assigned internal tracking number for the violation record, used for cross-referencing with SAP S/4HANA compliance modules and Enablon HSE Management case management.',
    `issuing_authority_type` STRING COMMENT 'Classification of the issuing authority jurisdiction: federal (EPA, BSEE, OSHA, PHMSA, FERC, BOEM, SEC), state (state environmental or safety agency), local (municipal authority), international (OPEC, foreign regulator), or internal_audit (company internal compliance or HSE audit finding).. Valid values are `federal|state|local|international|internal_audit`',
    `jurisdiction` STRING COMMENT 'Geographic or regulatory jurisdiction in which the violation occurred and is being adjudicated (e.g., US state code such as TX, LA, AK, or country code such as USA, GBR, NGA). Supports multi-jurisdictional compliance reporting and OPEC quota compliance tracking.. Valid values are `^[A-Z]{2,3}$`',
    `nov_issue_date` DATE COMMENT 'Date the Notice of Violation (NOV) or formal non-compliance finding was officially issued by the regulatory authority or internal audit function. Used to calculate regulatory response deadlines and statute of limitations.',
    `nov_number` STRING COMMENT 'Externally assigned Notice of Violation (NOV) number or citation reference issued by the regulatory authority. Serves as the official government-assigned identifier for the violation. Used for regulatory correspondence and closure documentation.',
    `penalty_amount` DECIMAL(18,2) COMMENT 'Gross monetary penalty assessed by the regulatory authority for the violation, in the currency specified by penalty_currency. Null if no monetary penalty has been assessed. Used for financial exposure tracking, CAPEX/OPEX impact analysis, and SEC disclosure assessment.',
    `penalty_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the assessed penalty amount (e.g., USD, EUR, GBP). Supports multi-currency operations for international regulatory jurisdictions.. Valid values are `^[A-Z]{3}$`',
    `penalty_paid_date` DATE COMMENT 'Date the monetary penalty was paid in full or the final installment was remitted to the regulatory authority. Null if payment has not been completed. Used for financial reconciliation in SAP S/4HANA FI module.',
    `penalty_payment_status` STRING COMMENT 'Current payment status of the assessed monetary penalty: not_assessed (no penalty levied), assessed_unpaid (penalty issued but not yet paid), partially_paid, paid_in_full, waived (penalty formally waived by authority), or under_appeal (payment suspended pending appeal outcome).. Valid values are `not_assessed|assessed_unpaid|partially_paid|paid_in_full|waived|under_appeal`',
    `regulation_cited` STRING COMMENT 'Specific regulation, rule, statute, or standard cited in the violation (e.g., 40 CFR Part 60 Subpart OOOO, 30 CFR Part 250, 29 CFR 1910.119, 49 CFR Part 195, FERC Order 636, SOX Section 302/404). Enables regulatory citation tracking and trend analysis by rule.',
    `regulatory_program` STRING COMMENT 'Name of the specific regulatory program or framework under which the violation was cited (e.g., Clean Air Act Title V, NPDES Stormwater, BSEE SEMS, OSHA PSM, PHMSA Integrity Management, SEC Regulation S-K, FERC Gas Tariff, BOEM OCSLA). Enables program-specific compliance trend analysis.',
    `repeat_violation` BOOLEAN COMMENT 'Indicates whether this violation is a repeat occurrence of a previously cited violation at the same facility or for the same regulation within the lookback period defined by the issuing authority. True if repeat; False if first occurrence. Repeat violations typically attract enhanced penalties under EPA, OSHA, and BSEE enforcement policies.',
    `resolution_status` STRING COMMENT 'Current lifecycle status of the violation record: open (newly identified, no action taken), in_progress (corrective action underway), closed (fully resolved and verified), appealed (formal appeal filed with authority), contested (company disputes the finding), pending_verification (corrective action completed, awaiting regulatory confirmation). Drives compliance calendar and SOX control reporting.. Valid values are `open|in_progress|closed|appealed|contested|pending_verification`',
    `response_due_date` DATE COMMENT 'Regulatory deadline by which the company must submit a formal response, corrective action plan, or abatement plan to the issuing authority. Drives compliance calendar alerts and SOX control monitoring.',
    `root_cause` STRING COMMENT 'Identified root cause of the violation as determined through investigation (e.g., equipment failure, procedural non-compliance, human error, inadequate training, design deficiency, management system gap). Supports corrective action planning and recurrence prevention.',
    `root_cause_category` STRING COMMENT 'Standardized category of the root cause for trend analysis and systemic issue identification: equipment_failure, human_error, procedural (non-compliance with procedure), management_system (gap in management system), design_deficiency, or external_factor (weather, third-party action).. Valid values are `equipment_failure|human_error|procedural|management_system|design_deficiency|external_factor`',
    `sec_disclosure_required` BOOLEAN COMMENT 'Indicates whether the violation meets the materiality threshold requiring disclosure in SEC filings (10-K, 10-Q, 8-K) under SEC Regulation S-K Item 103 (legal proceedings) or other applicable disclosure requirements. True if disclosure is required; False otherwise.',
    `severity_level` STRING COMMENT 'Severity classification of the violation indicating its potential impact on operations, environment, safety, or regulatory standing. Critical: immediate threat to life, environment, or operations; Major: significant regulatory exposure; Moderate: notable non-compliance; Minor: administrative or procedural; Informational: observation only.. Valid values are `critical|major|moderate|minor|informational`',
    `sox_control_reference` STRING COMMENT 'Reference to the specific SOX internal control or control objective that was impacted or tested as a result of this violation. Used for SOX Section 302/404 compliance documentation and internal control deficiency reporting.',
    `start_date` DATE COMMENT 'Date the non-compliant condition or activity began, as determined by investigation or regulatory finding. Used to calculate duration of non-compliance and assess penalty exposure under per-day penalty frameworks (e.g., EPA Clean Air Act, PHMSA).',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the violation record in the compliance management system. Supports change tracking, audit trail requirements, and incremental data loading in the Databricks Silver Layer.',
    `violation_category` STRING COMMENT 'High-level domain category of the violation: environmental (emissions, spills, waste), safety (HSE/OSHA), financial (SEC/SOX/COPAS), operational (production, process), reporting (regulatory filings), or permitting (permit/license compliance). Supports ESG reporting and compliance dashboard segmentation.. Valid values are `environmental|safety|financial|operational|reporting|permitting`',
    `violation_description` STRING COMMENT 'Detailed narrative description of the non-compliant condition, activity, or omission as stated in the NOV or internal audit finding. Includes the specific regulatory requirement that was not met and the observed deviation.',
    `violation_type` STRING COMMENT 'Classification of the violation by its nature: regulatory citation (specific rule breach), permit condition (permit term exceeded), license condition, reporting failure (missed or inaccurate filing), operational exceedance (production/emission limit exceeded), safety violation, environmental exceedance, or financial reporting non-compliance. [ENUM-REF-CANDIDATE: regulatory_citation|permit_condition|license_condition|reporting_failure|operational_exceedance|safety_violation|environmental_exceedance|financial_reporting — promote to reference product]',
    CONSTRAINT pk_violation PRIMARY KEY(`violation_id`)
) COMMENT 'Transactional record of each regulatory violation, notice of violation (NOV), or non-compliance finding issued by a regulatory authority or identified through internal audit. Tracks violation type, issuing authority, regulation cited, facility or asset involved, discovery date, severity classification, corrective action plan (CAPA details including responsible party, target date, completion date, verification method, effectiveness review), monetary penalties assessed (amount, payment status, appeal status), and resolution status. Supports SOX internal controls, ESG reporting, and regulatory closure documentation.';

CREATE OR REPLACE TABLE `oil_gas_ecm`.`compliance`.`compliance_corrective_action` (
    `compliance_corrective_action_id` BIGINT COMMENT 'Unique system-generated identifier for the corrective and preventive action (CAPA) record. Primary key for the corrective_action data product. [Role: TRANSACTION_HEADER]',
    `asset_facility_id` BIGINT COMMENT 'Identifier of the facility, installation, or asset location where the violation or compliance gap occurred and where the corrective action is being implemented (e.g., offshore platform, refinery, pipeline segment, processing plant).',
    `contract_id` BIGINT COMMENT 'Foreign key linking to procurement.procurement_contract. Business justification: Long-term remediation projects or recurring compliance services use service contracts. Real business process: remediation services contracting. Links CAPA to master service agreement when corrective a',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: CAPA implementation costs (estimated_cost_usd, actual_cost_usd) are allocated to cost centers for budget tracking, variance analysis, and joint venture billing. Critical for matching corrective action',
    `drilling_well_id` BIGINT COMMENT 'Foreign key linking to drilling.drilling_well. Business justification: Corrective actions for well-related violations (barrier failures, permit non-compliance) must link to well records for tracking remediation and regulatory closure. Api_well_number exists but FK ensure',
    `equipment_id` BIGINT COMMENT 'Foreign key linking to asset.equipment. Business justification: Corrective actions frequently target specific equipment (e.g., replace PRV, repair compressor seal, retrofit emission controls). compliance_corrective_action links to asset_facility but not equipment;',
    `finance_afe_id` BIGINT COMMENT 'Foreign key linking to finance.finance_afe. Business justification: Major corrective actions (facility modifications, equipment upgrades) are capitalized under AFEs for asset tracking and depreciation. Links actual_cost_usd to AFE budget and enables capital vs. expens',
    `inspection_event_id` BIGINT COMMENT 'Foreign key linking to asset.inspection_event. Business justification: Corrective actions are triggered by specific inspection event findings (e.g., corrosion anomaly found during ILI, defect found during pressure test). Linking CAPA to triggering inspection event enable',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to procurement.material_master. Business justification: Corrective actions requiring specific materials or parts (replacement valves, safety equipment). Real business process: corrective action materials planning. Links CAPA to specific material when equip',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: A corrective action addresses a specific compliance obligation that was found to be deficient. Linking compliance_corrective_action to obligation enables tracking of which regulatory obligations are d',
    `permit_id` BIGINT COMMENT 'Reference to the regulatory permit or license record associated with this corrective action, when the action is required to maintain permit compliance or restore permit conditions (e.g., air permit, discharge permit, drilling permit).',
    `petroleum_product_id` BIGINT COMMENT 'Foreign key linking to product.petroleum_product. Business justification: Corrective actions address product quality failures (reformulation to meet specifications, product recall, blending corrections) and specification violations. Links remediation activities to specific ',
    `pipeline_segment_id` BIGINT COMMENT 'Foreign key linking to asset.pipeline_segment. Business justification: Corrective actions for pipeline integrity violations (PHMSA IMP findings, corrosion anomalies) target specific pipeline segments. Segment-level CAPA tracking is required for PHMSA IMP compliance and p',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Corrective actions address compliance issues at specific facilities/operations; actual and estimated costs must be allocated to profit centers for accurate segment P&L, budget tracking, and management',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Corrective actions requiring equipment or materials trigger purchase orders. Real business process: corrective action procurement execution. Links CAPA to specific PO when materials/equipment purchase',
    `regulatory_audit_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_audit. Business justification: A corrective action can be initiated directly in response to a regulatory audit finding, independent of a formal violation record. Linking compliance_corrective_action to regulatory_audit enables trac',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Corrective actions often require vendor services (remediation contractors, equipment suppliers, consulting engineers). Real business process: corrective action execution via procurement. Links CAPA to',
    `violation_id` BIGINT COMMENT 'Foreign key linking to compliance.violation. Business justification: A corrective action (CAPA) is initiated in response to a specific regulatory violation. This is the primary business trigger for a CAPA in the compliance domain. Linking compliance_corrective_action t',
    `well_asset_id` BIGINT COMMENT 'Foreign key linking to asset.well_asset. Business justification: Corrective actions for well integrity violations (e.g., casing repair, mechanical integrity test remediation) target specific wells. Well-level CAPA tracking is required for UIC program compliance and',
    `action_description` STRING COMMENT 'Detailed narrative describing the specific corrective or preventive action to be taken, including the scope of work, methodology, and expected outcome. Supports regulatory closure documentation and audit evidence packages.',
    `action_status` STRING COMMENT 'Current lifecycle state of the corrective action record. Drives compliance calendar tracking and regulatory closure documentation. Transitions: open → in_progress → pending_verification → closed. Overdue is a system-flagged state when target completion date is exceeded.. Valid values are `open|in_progress|pending_verification|closed|overdue|cancelled`',
    `action_title` STRING COMMENT 'Short, descriptive title summarizing the corrective action. Used as the primary display label in compliance dashboards, regulatory submissions, and management reports.',
    `action_type` STRING COMMENT 'Classification of the action as corrective (addressing a known violation or nonconformance), preventive (proactively eliminating potential causes), immediate (emergency interim measure), systemic (root-cause-driven process change), or regulatory_directed (mandated by a regulatory authority such as BSEE, EPA, or PHMSA).. Valid values are `corrective|preventive|immediate|systemic|regulatory_directed`',
    `actual_completion_date` DATE COMMENT 'Date on which the corrective action was fully implemented and all required activities were completed. Compared against target_completion_date to assess timeliness and regulatory compliance. Null until the action is completed.',
    `actual_cost_usd` DECIMAL(18,2) COMMENT 'Actual total cost in US dollars incurred to implement the corrective action upon completion. Compared against estimated_cost_usd for budget variance analysis and financial reporting. Null until the action is completed and costs are finalized.',
    `capa_number` STRING COMMENT 'Externally-known, human-readable reference number assigned to the corrective and preventive action record. Used in regulatory submissions, audit correspondence, and government reporting. Format: CAPA-YYYY-NNNNNN.. Valid values are `^CAPA-[0-9]{4}-[0-9]{6}$`',
    `comments` STRING COMMENT 'Free-text field for additional notes, management commentary, or contextual information related to the corrective action that does not fit into structured fields. Supports audit trail documentation and regulatory correspondence.',
    `compliance_domain` STRING COMMENT 'Business compliance domain to which this corrective action belongs, enabling cross-domain analytics and portfolio management. [ENUM-REF-CANDIDATE: hse|environmental|financial|operational|safety|pipeline|offshore|reserves|process_safety|esg — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this corrective action record was first created in the data system. Distinct from initiated_timestamp which reflects the business event time. Supports SOX audit trail requirements.',
    `effectiveness_review_date` DATE COMMENT 'Date on which the effectiveness review was conducted to assess whether the corrective action successfully prevented recurrence of the violation or compliance gap. Typically performed 30-90 days after action closure.',
    `effectiveness_review_notes` STRING COMMENT 'Narrative documentation of the effectiveness review findings, including evidence of recurrence prevention, residual risks identified, and any follow-up actions recommended. Supports regulatory audit evidence packages.',
    `effectiveness_review_status` STRING COMMENT 'Outcome of the post-implementation effectiveness review assessing whether the corrective action successfully eliminated the root cause and prevented recurrence. Supports continuous improvement tracking and regulatory audit readiness.. Valid values are `pending|effective|partially_effective|ineffective|not_required`',
    `esg_category` STRING COMMENT 'ESG reporting category to which this corrective action contributes, enabling aggregation for ESG disclosures, sustainability reports, and investor reporting. [ENUM-REF-CANDIDATE: environmental|social|governance|safety|ghg_emissions|spill|waste|biodiversity|human_rights — promote to reference product]',
    `estimated_cost_usd` DECIMAL(18,2) COMMENT 'Estimated total cost in US dollars to implement the corrective action, including labor, materials, contractor services, and equipment. Used for CAPEX/OPEX budgeting, AFE preparation, and financial reporting under SOX and IFRS/GAAP.',
    `initiated_timestamp` TIMESTAMP COMMENT 'Date and time when the corrective action was formally initiated and entered into the compliance management system. Represents the principal business event timestamp for this transaction. Used to calculate response time against regulatory deadlines.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording the most recent modification to this corrective action record. Supports change tracking, SOX internal controls, and regulatory audit trail documentation.',
    `priority_level` STRING COMMENT 'Business priority assigned to the corrective action based on regulatory risk, safety impact, and potential penalty exposure. Critical actions typically involve imminent regulatory deadlines or safety-critical systems (e.g., BOP integrity, H2S exposure controls).. Valid values are `critical|high|medium|low`',
    `recurrence_flag` BOOLEAN COMMENT 'Indicates whether this corrective action addresses a recurring violation or compliance gap that has previously been subject to a corrective action. Recurrence triggers escalated regulatory scrutiny and may indicate systemic management system failure under BSEE SEMS II.',
    `regulatory_authority` STRING COMMENT 'The regulatory body or governing authority whose requirement, inspection finding, or directive triggered or is associated with this corrective action (e.g., BSEE for offshore safety, EPA for environmental violations, PHMSA for pipeline safety, OSHA for workplace safety). [ENUM-REF-CANDIDATE: BSEE|EPA|PHMSA|OSHA|FERC|BOEM|SEC|OPEC|API|STATE|OTHER — promote to reference product]',
    `regulatory_citation` STRING COMMENT 'Specific regulatory code, rule, or standard citation that was violated or is being addressed by this corrective action (e.g., 30 CFR 250.1920, 40 CFR 60.18, 49 CFR 195.452). Used in regulatory correspondence and closure documentation.',
    `regulatory_closure_date` DATE COMMENT 'Date on which the regulatory authority formally acknowledged and accepted the closure of the corrective action, confirming that all regulatory requirements have been satisfied. Null until regulatory closure is confirmed.',
    `regulatory_closure_required` BOOLEAN COMMENT 'Indicates whether formal regulatory closure documentation must be submitted to a regulatory authority (e.g., BSEE, EPA, PHMSA) upon completion of this corrective action. Drives the compliance calendar and submission workflow.',
    `regulatory_deadline_date` DATE COMMENT 'Externally mandated deadline imposed by a regulatory authority (e.g., BSEE, EPA, PHMSA) for completion of the corrective action. Distinct from the internal target_completion_date. Breach of this date may result in penalties, fines, or escalated enforcement action.',
    `regulatory_submission_ref` STRING COMMENT 'Reference number or tracking identifier assigned by the regulatory authority upon submission of the corrective action plan or closure documentation (e.g., BSEE incident number, EPA enforcement case number, PHMSA corrective action order number).',
    `responsible_department` STRING COMMENT 'Organizational department or business unit accountable for executing the corrective action (e.g., HSE, Drilling, Production, Refining, Regulatory Affairs). Used for workload distribution reporting and compliance performance analytics.',
    `responsible_party_name` STRING COMMENT 'Full name of the individual assigned as the primary owner accountable for executing and completing the corrective action. Retained directly on the record for regulatory reporting and audit documentation where the workforce system may not be accessible.',
    `root_cause_category` STRING COMMENT 'Standardized classification of the root cause type to enable trend analysis and systemic improvement tracking across the compliance portfolio. [ENUM-REF-CANDIDATE: human_factor|process_failure|equipment_failure|management_system|regulatory_gap|environmental|design_deficiency|contractor_performance — promote to reference product if additional categories are needed]. Valid values are `human_factor|process_failure|equipment_failure|management_system|regulatory_gap|environmental`',
    `root_cause_description` STRING COMMENT 'Narrative description of the identified root cause(s) of the violation, nonconformance, or compliance gap that necessitated this corrective action. Derived from root cause analysis (RCA) methodologies such as 5-Why or fishbone analysis.',
    `target_completion_date` DATE COMMENT 'Planned date by which the corrective action must be fully implemented and verified. May be set by internal management or mandated by a regulatory authority as part of a Notice of Violation (NOV) or Consent Order response deadline.',
    `verification_date` DATE COMMENT 'Date on which the verification activity was performed to confirm effective implementation of the corrective action. Required for regulatory closure packages submitted to BSEE, EPA, PHMSA, or other authorities.',
    `verification_method` STRING COMMENT 'Method used to verify that the corrective action has been effectively implemented. Options include physical inspection, internal audit, functional test, document review, field observation, or independent third-party audit as required by regulatory authorities.. Valid values are `inspection|audit|test|document_review|field_observation|third_party_audit`',
    CONSTRAINT pk_compliance_corrective_action PRIMARY KEY(`compliance_corrective_action_id`)
) COMMENT 'Transactional record of corrective and preventive actions (CAPAs) initiated in response to regulatory violations, audit findings, or compliance gaps. Tracks action description, responsible party, target completion date, actual completion date, verification method, effectiveness review, and linkage to the originating violation or audit finding. Supports regulatory closure documentation.';

CREATE OR REPLACE TABLE `oil_gas_ecm`.`compliance`.`regulatory_audit` (
    `regulatory_audit_id` BIGINT COMMENT 'Unique surrogate identifier for each regulatory audit or inspection record in the compliance domain. Primary key for the regulatory_audit data product.',
    `afe_budget_id` BIGINT COMMENT 'Foreign key linking to procurement.afe_budget. Business justification: Regulatory audits of capital projects (drilling programs, facility construction) require reference to the AFE for scope verification, cost validation, and compliance with authorized expenditures. This',
    `asset_facility_id` BIGINT COMMENT 'Reference to the facility, asset, or operational unit subject to the audit (e.g., offshore platform, refinery, pipeline segment, processing plant, well). Links the audit to the physical asset being inspected for asset-level compliance tracking.',
    `contract_id` BIGINT COMMENT 'Foreign key linking to procurement.procurement_contract. Business justification: Regulatory audit services procured via service contracts with auditing firms. Real business process: audit services contracting. Links audit to master service agreement for recurring audit services.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: External regulatory audits conducted by third-party auditing firms tracked as vendors. Real business process: regulatory audit services procurement. Replaces text auditing_authority with FK to vendor ',
    `certification_id` BIGINT COMMENT 'Foreign key linking to compliance.certification. Business justification: Regulatory audits are often performed to verify certifications (e.g., ISO audits, SEMS audits). The certification table has last_audit_date and next_audit_date suggesting audits are performed ON certi',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Audit preparation, response, and penalty costs are allocated to facility or compliance cost centers for budget tracking and variance analysis. Essential for tracking penalty_amount and remediation cos',
    `equipment_id` BIGINT COMMENT 'Foreign key linking to asset.equipment. Business justification: Regulatory audits (PSM audits, LDAR audits, EPA Method 21 inspections) focus on specific equipment items. regulatory_audit links to asset_facility but not equipment; equipment-level audit tracking is ',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: A regulatory audit verifies compliance with specific regulatory obligations. Linking regulatory_audit to the primary obligation being audited enables traceability from the obligation catalog to audit ',
    `petroleum_product_id` BIGINT COMMENT 'Foreign key linking to product.petroleum_product. Business justification: Regulatory audits examine product-specific quality programs, specification compliance, and testing protocols for individual petroleum products. EPA fuel audits, state fuel quality inspections, and avi',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Regulatory audits target specific operations/facilities within profit centers; audit costs, findings, and corrective action expenses must be allocated to profit centers for management accountability a',
    `regulatory_authority_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_authority. Business justification: A regulatory audit is conducted by a specific regulatory authority (e.g., BSEE conducts offshore safety audits, EPA conducts environmental compliance inspections). The regulatory_audit table has no FK',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_regulatory_filing. Business justification: A regulatory audit may be triggered by or result in a regulatory filing (e.g., an audit response submission to a regulatory body). Linking regulatory_audit to compliance_regulatory_filing enables trac',
    `well_asset_id` BIGINT COMMENT 'Foreign key linking to asset.well_asset. Business justification: Well integrity audits, UIC mechanical integrity tests, and plugging & abandonment audits are conducted on specific wells. regulatory_audit links to asset_facility but not well_asset; well-level audit ',
    `applicable_regulation` STRING COMMENT 'Primary regulatory citation or standard under which the audit is conducted (e.g., 30 CFR Part 250, 40 CFR Part 60, 29 CFR 1910.119, 49 CFR Part 195, SOX Section 404, API RP 75). Provides the legal basis for the audit and its findings.',
    `audit_end_date` DATE COMMENT 'The date on which the regulatory audit or inspection formally concluded. Nullable for audits still in progress. Used to compute audit duration and trigger post-audit reporting deadlines.',
    `audit_reference_number` STRING COMMENT 'Externally-known alphanumeric identifier assigned to the audit by the governing agency or internal compliance team (e.g., BSEE inspection number, EPA audit case number, OSHA citation number, internal SOX audit ID). Used for cross-referencing with agency records and regulatory submissions.',
    `audit_report_number` STRING COMMENT 'Official document number of the formal audit report issued by the auditing authority or internal compliance team. Used for document management, regulatory correspondence, and records retention compliance. Distinct from the audit_reference_number which is the case/inspection identifier.',
    `audit_scope` STRING COMMENT 'Narrative description of the regulatory areas, operational processes, systems, or equipment covered by the audit (e.g., Well control equipment and BOP testing procedures, Air emissions monitoring and LDAR program, Pipeline integrity management program, SOX IT general controls — SAP S/4HANA FI module). Defines the boundaries of the audit engagement.',
    `audit_start_date` DATE COMMENT 'The date on which the regulatory audit or inspection formally commenced. Used to calculate audit duration, track compliance calendar obligations, and support regulatory reporting timelines.',
    `audit_status` STRING COMMENT 'Current lifecycle state of the regulatory audit record, from scheduling through final closure. Drives compliance calendar management and escalation workflows.. Valid values are `SCHEDULED|IN_PROGRESS|COMPLETED|CLOSED|CANCELLED`',
    `audit_type` STRING COMMENT 'Classification of the audit or inspection by the type of regulatory authority or internal program conducting it. Drives applicable regulatory framework, citation standards, and reporting obligations. [ENUM-REF-CANDIDATE: BSEE_INSPECTION|EPA_AUDIT|OSHA_INSPECTION|PHMSA_INSPECTION|FERC_AUDIT|BOEM_INSPECTION|INTERNAL_SOX|INTERNAL_HSE — promote to reference product]',
    `cited_regulation` STRING COMMENT 'Specific regulatory citation, code section, or standard violated as identified in the finding (e.g., 30 CFR 250.440(a), 40 CFR 60.18(c), 29 CFR 1910.119(e)(1), API RP 14C Section 4.2). Provides the legal basis for each individual finding and drives citation-level compliance tracking.',
    `corrective_action_completed_date` DATE COMMENT 'Actual date on which the corrective action was completed and verified. Compared against corrective_action_due_date to assess timeliness of remediation. Required for regulatory closure submissions and SOX control effectiveness documentation.',
    `corrective_action_due_date` DATE COMMENT 'Deadline by which the corrective action for the finding must be completed, as stipulated by the regulatory agency or internal compliance policy. Drives compliance calendar management and escalation triggers for overdue remediation items.',
    `corrective_action_status` STRING COMMENT 'Current resolution status of the corrective action for the finding. OVERDUE status triggers escalation to compliance management and potential regulatory notification. Supports compliance dashboard reporting and audit closure tracking.. Valid values are `OPEN|IN_PROGRESS|COMPLETED|OVERDUE|WAIVED`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the jurisdiction where the audited facility or operation is located (e.g., USA, GBR, NOR, SAU). Supports multinational compliance reporting, ESG disclosures, and country-level regulatory obligation tracking.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the regulatory audit record was first created in the compliance management system. Supports audit trail integrity, SOX internal control documentation, and data lineage tracking in the Databricks Silver Layer.',
    `critical_finding_count` STRING COMMENT 'Number of findings classified as critical or high-risk severity within this audit. Critical findings typically require immediate corrective action and executive notification. Supports risk-based compliance prioritization and SEC/BSEE mandatory disclosure assessments.',
    `esg_category` STRING COMMENT 'ESG pillar classification of the audit for sustainability and ESG reporting purposes. Environmental audits cover GHG emissions, LDAR, spill prevention. Social audits cover OSHA safety, workforce. Governance audits cover SOX, FCPA, financial controls. Supports ESG disclosure obligations under SEC climate rules, GRI, and SASB Oil & Gas Standard.. Valid values are `ENVIRONMENTAL|SOCIAL|GOVERNANCE|SAFETY|COMBINED`',
    `facility_name` STRING COMMENT 'Human-readable name of the facility, asset, or operational unit subject to the audit (e.g., Thunder Horse PDQ Platform, Baytown Refinery, Gulf Coast Pipeline Segment 7). Retained for reporting and audit trail clarity independent of the facility master record.',
    `facility_type` STRING COMMENT 'Classification of the audited facility or asset by operational category. Determines applicable regulatory standards and inspection protocols. FPSO = Floating Production Storage and Offloading. [ENUM-REF-CANDIDATE: OFFSHORE_PLATFORM|ONSHORE_WELL|REFINERY|PIPELINE|PROCESSING_PLANT|TERMINAL|FPSO|PETROCHEMICAL_PLANT — promote to reference product]',
    `finding_count` STRING COMMENT 'Total number of individual findings, deficiencies, or observations identified during the audit. Provides a summary metric for audit severity assessment and compliance trend analysis without requiring aggregation of the findings detail records.',
    `finding_description` STRING COMMENT 'Detailed narrative description of the specific deficiency, non-conformance, or observation identified during the audit. Includes the nature of the violation, the condition observed, and the regulatory requirement that was not met. Core field for corrective action planning and regulatory response.',
    `finding_risk_classification` STRING COMMENT 'Risk severity level assigned to the individual finding based on potential safety, environmental, financial, or regulatory impact. CRITICAL findings may require immediate shutdown or regulatory notification. Drives corrective action prioritization and escalation protocols per HSE and SOX frameworks.. Valid values are `CRITICAL|HIGH|MEDIUM|LOW|OBSERVATION`',
    `ghg_related` BOOLEAN COMMENT 'Indicates whether the audit involves greenhouse gas emissions compliance, including methane emissions monitoring, GHG reporting under EPA 40 CFR Part 98, or carbon capture and storage (CCS) program compliance. Supports ESG reporting and SEC climate disclosure obligations.',
    `h2s_related` BOOLEAN COMMENT 'Indicates whether the audit involves H2S (Hydrogen Sulfide) safety compliance, including detection systems, emergency response plans, and worker protection measures. H2S is a critical safety hazard in oil and gas operations subject to OSHA 29 CFR 1910.119 and API RP 55.',
    `is_repeat_finding` BOOLEAN COMMENT 'Indicates whether the finding is a recurrence of a previously identified deficiency at the same facility or for the same regulatory requirement. Repeat findings typically attract enhanced regulatory scrutiny, higher penalties, and mandatory escalation under BSEE, EPA, and OSHA enforcement policies.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the regulatory audit record was most recently modified. Supports change tracking, SOX internal control documentation, and incremental data processing in the Databricks Silver Layer lakehouse architecture.',
    `lead_auditor_name` STRING COMMENT 'Full name of the primary auditor or inspector responsible for conducting the audit. For government inspections, this is the agency inspector of record. For internal audits, this is the lead internal auditor. Required for audit trail integrity and regulatory correspondence.',
    `norm_related` BOOLEAN COMMENT 'Indicates whether the audit involves NORM (Naturally Occurring Radioactive Material) compliance, which is a specific regulatory concern in oil and gas production operations. NORM findings require specialized handling, disposal, and regulatory reporting under EPA and state radiation control programs.',
    `overall_outcome` STRING COMMENT 'The aggregate result or conclusion of the audit as determined by the auditing authority. Drives escalation, enforcement action, and executive compliance reporting. A VIOLATION_ISSUED outcome triggers mandatory corrective action tracking and potential regulatory penalty assessment.. Valid values are `SATISFACTORY|CONDITIONAL|UNSATISFACTORY|VIOLATION_ISSUED|PENDING_REVIEW`',
    `penalty_amount` DECIMAL(18,2) COMMENT 'Monetary penalty or fine assessed by the regulatory agency as a result of the audit findings, expressed in the reporting currency. Nullable when no financial penalty is assessed. Supports financial liability tracking, CAPEX/OPEX impact analysis, and SEC disclosure obligations for material regulatory penalties.',
    `penalty_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the penalty amount (e.g., USD, GBP, EUR). Required for multinational operations where penalties may be assessed in local currency. Supports financial consolidation and IFRS/GAAP reporting.. Valid values are `^[A-Z]{3}$`',
    `penalty_payment_due_date` DATE COMMENT 'Deadline by which the assessed regulatory penalty must be paid to the governing agency. Drives accounts payable scheduling and financial liability management. Nullable when no penalty is assessed.',
    `prior_audit_reference` STRING COMMENT 'Reference number of the prior audit in which the same or related finding was previously identified. Used to establish repeat-finding linkage for regulatory enforcement escalation and trend analysis. Nullable for first-occurrence findings.',
    `recommended_corrective_action` STRING COMMENT 'Narrative description of the corrective action recommended by the auditor to remediate the identified finding. May be prescribed by the regulatory agency or proposed by the internal compliance team. Forms the basis for the corrective action plan (CAP) and regulatory response submissions.',
    `regulatory_jurisdiction` STRING COMMENT 'Geographic or legal jurisdiction under which the audit is conducted (e.g., Federal — Gulf of Mexico OCS, State — Texas Railroad Commission, Federal — EPA Region 6, International — North Sea UKCS). Determines applicable regulatory framework and reporting obligations for multinational operations.',
    `regulatory_program` STRING COMMENT 'The specific regulatory program or rule set under which the audit is conducted (e.g., SEMS — Safety and Environmental Management System, LDAR — Leak Detection and Repair, Pipeline Integrity Management, SEC Reserves Disclosure, OPEC Quota Compliance, ESG Reporting). Maps the audit to the governing compliance framework.',
    `report_issued_date` DATE COMMENT 'Date on which the formal audit report was officially issued by the auditing authority or internal compliance team. Triggers response deadlines and corrective action plan submission timelines under applicable regulatory frameworks.',
    `response_due_date` DATE COMMENT 'Deadline by which the company must submit a formal written response or corrective action plan to the auditing authority. Calculated from report_issued_date per applicable regulatory requirements. Drives compliance calendar management and escalation workflows.',
    `response_submitted_date` DATE COMMENT 'Actual date on which the company submitted its formal written response or corrective action plan to the auditing authority. Compared against response_due_date to assess regulatory response timeliness and compliance with submission deadlines.',
    `responsible_party` STRING COMMENT 'Name or identifier of the individual, team, or organizational unit accountable for implementing the corrective action for the finding. Typically the operations manager, HSE manager, or process owner for the audited facility or function.',
    CONSTRAINT pk_regulatory_audit PRIMARY KEY(`regulatory_audit_id`)
) COMMENT 'Master record of regulatory audits and inspections conducted by government agencies or internal compliance teams, including individual findings. Tracks audit type (BSEE inspection, EPA audit, OSHA inspection, internal SOX audit), auditing authority, facility or asset audited, audit date range, lead auditor, scope, overall audit outcome, and detailed findings (specific deficiency, regulation cited, risk classification, recommended corrective action, responsible party, resolution status). Distinct from HSE incident records — this captures formal compliance audit events and their outcomes.';

CREATE OR REPLACE TABLE `oil_gas_ecm`.`compliance`.`consent_order` (
    `consent_order_id` BIGINT COMMENT 'Unique surrogate identifier for the consent order record in the lakehouse silver layer. Primary key. Entity role: MASTER_AGREEMENT — a binding regulatory instrument with its own lifecycle, effective dates, and compliance obligations.',
    `afe_budget_id` BIGINT COMMENT 'Foreign key linking to procurement.afe_budget. Business justification: Consent orders requiring remediation, facility upgrades, or environmental restoration are funded through dedicated AFE budgets. Linking consent order to AFE enables tracking remediation costs, managin',
    `asset_facility_id` BIGINT COMMENT 'Reference to the primary facility, plant, refinery, offshore platform, pipeline segment, or operational asset subject to the consent order. Links to the asset management domain for facility-level compliance tracking.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Consent order fulfillment costs (SEP projects, monitoring, reporting) are allocated to cost centers for compliance budget tracking and variance analysis. Essential for tracking milestone completion co',
    `counterparty_id` BIGINT COMMENT 'Foreign key linking to customer.customer_counterparty. Business justification: Consent orders target counterparties as responsible parties for enforcement. Real process: tracking which counterparty is subject to enforcement actions for joint venture liability allocation, operato',
    `drilling_well_id` BIGINT COMMENT 'Foreign key linking to drilling.drilling_well. Business justification: Consent orders are frequently issued against specific wells for well integrity violations, improper P&A, or environmental releases. Linking consent_order to drilling_well enables well-level legal obli',
    `petroleum_product_id` BIGINT COMMENT 'Foreign key linking to product.petroleum_product. Business justification: Consent orders may mandate product-specific actions: reformulation requirements, specification changes, product discontinuation, or enhanced testing protocols. Links legal settlement terms to affected',
    `pipeline_segment_id` BIGINT COMMENT 'Foreign key linking to asset.pipeline_segment. Business justification: PHMSA consent orders and state pipeline safety consent agreements target specific pipeline segments (e.g., pressure reduction orders, repair mandates). Segment-level consent order tracking is required',
    `production_facility_id` BIGINT COMMENT 'EPA Facility Registry Service (FRS) unique identifier for the regulated facility associated with this consent order. Used for cross-referencing EPA enforcement databases (ECHO, ICIS) and regulatory submissions.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Consent orders relate to specific facilities/operations within profit centers; remediation costs, penalties, and ongoing compliance costs must be tracked at profit center level for segment P&L and per',
    `regulatory_authority_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_authority. Business justification: A consent order is issued by a specific regulatory authority (e.g., EPA consent decrees, state environmental agency consent orders). The consent_order table has issuing_agency as a STRING which is den',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Consent orders are submitted to and approved by regulatory authorities, making them regulatory filings. Adding regulatory_filing_id FK links the consent order to its filing record, enabling tracking o',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Consent order fulfillment often requires vendor services (environmental remediation contractors, monitoring equipment suppliers). Real business process: consent order compliance execution via procurem',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Consent orders are issued against legal entities (accounts) for enforcement actions. Real process: tracking which account is subject to each consent order for compliance monitoring, financial accruals',
    `violation_id` BIGINT COMMENT 'Foreign key linking to compliance.violation. Business justification: A consent order is entered into to resolve a specific regulatory violation or enforcement action. Linking consent_order to the primary violation it resolves provides the enforcement chain from violati',
    `well_asset_id` BIGINT COMMENT 'Foreign key linking to asset.well_asset. Business justification: Consent orders are issued against specific wells (e.g., well integrity consent orders, plugging orders, spill remediation orders). consent_order links to asset_facility but not well_asset; well-level ',
    `agency_case_officer` STRING COMMENT 'Name of the primary regulatory agency enforcement officer or case manager responsible for overseeing compliance with this consent order. Used for correspondence, milestone reporting submissions, and audit trail.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code for the country in which the consent order has legal effect (e.g., USA, GBR, NOR). Supports multinational compliance tracking.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this consent order record was first created in the lakehouse silver layer, in ISO 8601 format with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports audit trail and data lineage requirements.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts in this consent order record (e.g., USD, GBP, EUR). Supports multinational financial reporting under IFRS/GAAP.. Valid values are `^[A-Z]{3}$`',
    `effective_date` DATE COMMENT 'Date on which the consent order becomes legally binding and enforceable, as stipulated in the instrument. Marks the start of the compliance obligation period and triggers milestone scheduling.',
    `enablon_case_ref` STRING COMMENT 'Reference identifier for the corresponding enforcement case or compliance obligation record in the Enablon HSE Management system. Enables traceability between the lakehouse silver layer and the operational system of record.',
    `execution_date` DATE COMMENT 'Date on which the consent order was formally signed or entered by all parties (company and regulatory agency), which may differ from the effective date. Represents the principal real-world business event timestamp for this agreement.',
    `expiration_date` DATE COMMENT 'Date on which the consent order expires or all obligations are scheduled to be fully discharged, as specified in the instrument. Null for open-ended orders with no fixed termination. Used for compliance calendar management.',
    `fulfillment_status` STRING COMMENT 'Current operational fulfillment status of the consent orders compliance obligations: on_track (milestones being met), at_risk (potential delay identified), overdue (missed milestone or report), fulfilled (all obligations satisfied), or partially_fulfilled (some milestones complete). Distinct from order_status which reflects the legal lifecycle.. Valid values are `on_track|at_risk|overdue|fulfilled|partially_fulfilled`',
    `ghg_related` BOOLEAN COMMENT 'Indicates whether the consent order relates to greenhouse gas (GHG) emissions violations, including methane, CO2, or other regulated GHG emissions under EPA Clean Air Act or state equivalents. Supports GHG compliance and ESG reporting.',
    `hse_classification` STRING COMMENT 'HSE domain classification of the consent order: environmental (spills, emissions, waste disposal), safety (worker safety, OSHA), health (occupational health), process_safety (PSM, BSEE), or combined (multiple HSE domains). Aligns with Enablon HSE Management categorization.. Valid values are `environmental|safety|health|process_safety|combined`',
    `is_esg_reportable` BOOLEAN COMMENT 'Indicates whether this consent order must be disclosed in the companys ESG or sustainability report. True for orders involving GHG emissions, environmental spills, HSE violations, or other ESG-material events.',
    `is_sec_reportable` BOOLEAN COMMENT 'Indicates whether this consent order meets the materiality threshold requiring disclosure in SEC filings under Regulation S-K Item 103 (Legal Proceedings). True if the penalty exceeds $300,000 or is otherwise material to investors.',
    `jurisdiction_level` STRING COMMENT 'Level of governmental jurisdiction under which the consent order was issued: federal (EPA, BSEE, OSHA, PHMSA, FERC, BOEM), state (state environmental or safety agency), local (county or municipal authority), or international (foreign regulatory body). Determines reporting chain and legal venue.. Valid values are `federal|state|local|international`',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter U.S. state code (FIPS/USPS standard) for the state in which the consent order has legal effect, or the state agency that issued it. Null for purely federal or international orders.. Valid values are `^[A-Z]{2}$`',
    `last_report_submitted_date` DATE COMMENT 'Date on which the most recent mandatory compliance progress report was submitted to the issuing regulatory agency. Used to verify reporting cadence adherence and identify overdue submissions.',
    `legal_counsel_name` STRING COMMENT 'Name of the internal or external legal counsel representing the company in negotiations and ongoing compliance management for this consent order. Supports attorney-client privilege tracking and legal matter management.',
    `milestone_count` STRING COMMENT 'Total number of distinct compliance milestones or deliverables stipulated in the consent order (e.g., equipment installation deadlines, audit submissions, monitoring report due dates). Used for progress tracking and compliance calendar population.',
    `milestones_completed_count` STRING COMMENT 'Number of compliance milestones that have been fulfilled and accepted by the regulatory agency to date. Compared against milestone_count to assess overall fulfillment progress.',
    `next_milestone_due_date` DATE COMMENT 'Date by which the next outstanding compliance milestone or deliverable must be completed and submitted to the regulatory agency. Drives compliance calendar alerts and escalation workflows in Enablon HSE Management.',
    `next_report_due_date` DATE COMMENT 'Date by which the next mandatory progress or compliance status report must be submitted to the issuing regulatory agency under the consent orders reporting obligations.',
    `order_number` STRING COMMENT 'Externally-known docket or case number assigned by the issuing regulatory agency to uniquely identify this consent order, consent decree, or settlement agreement (e.g., EPA Docket No. CAA-06-2023-0042). Used for all regulatory correspondence and submissions.',
    `order_status` STRING COMMENT 'Current lifecycle state of the consent order: active (in force and obligations ongoing), fulfilled (all milestones and penalties satisfied), terminated (voided or withdrawn), superseded (replaced by a subsequent order), or under_negotiation (draft stage prior to execution). Drives compliance calendar and SOX disclosure.. Valid values are `active|fulfilled|terminated|superseded|under_negotiation`',
    `order_title` STRING COMMENT 'Official short title or caption of the consent order as designated by the issuing agency, used for identification in regulatory filings, internal compliance registers, and SEC disclosure documents.',
    `order_type` STRING COMMENT 'Classification of the regulatory instrument: consent_order (administrative), consent_decree (judicial/court-entered), settlement_agreement (negotiated resolution), administrative_order (unilateral agency directive), or compliance_order (corrective mandate). Determines legal enforceability and reporting treatment.. Valid values are `consent_order|consent_decree|settlement_agreement|administrative_order|compliance_order`',
    `regulation_citation` STRING COMMENT 'Specific statutory or regulatory citation(s) that form the legal basis for the consent order (e.g., Clean Air Act § 113(d), 40 CFR Part 60, 30 CFR § 250.401). Supports regulatory compliance mapping and legal review.',
    `reporting_frequency` STRING COMMENT 'Frequency at which progress reports must be submitted to the issuing regulatory agency under the terms of the consent order: monthly, quarterly, semi_annual, annual, one_time, or as_required. Populates the compliance obligation calendar.. Valid values are `monthly|quarterly|semi_annual|annual|one_time|as_required`',
    `responsible_business_unit` STRING COMMENT 'Name of the internal business unit, division, or operating company accountable for managing compliance with this consent order (e.g., Upstream E&P, Refining and Marketing, Midstream Pipeline Operations). Aligns with SAP CO cost center hierarchy.',
    `sap_legal_case_number` STRING COMMENT 'Reference number for the corresponding legal case or provision record in SAP S/4HANA (FI/Legal module) used for financial provisioning, penalty accruals, and CAPEX/OPEX cost tracking associated with this consent order.',
    `sep_credit_amount` DECIMAL(18,2) COMMENT 'Dollar value of penalty mitigation credit granted for Supplemental Environmental Projects (SEPs) agreed to as part of the consent order settlement. SEPs are environmentally beneficial projects that reduce the net cash penalty obligation. Specific to EPA enforcement settlements.',
    `stipulated_penalty_per_day` DECIMAL(18,2) COMMENT 'Daily stipulated penalty amount (in the designated currency) that accrues for each day of non-compliance with a milestone or reporting obligation under the consent order. Critical for financial risk quantification and CAPEX/OPEX planning.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this consent order record was most recently modified in the lakehouse silver layer, in ISO 8601 format with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports change tracking, audit trail, and SOX internal controls.',
    CONSTRAINT pk_consent_order PRIMARY KEY(`consent_order_id`)
) COMMENT 'Master record of consent orders, consent decrees, and settlement agreements entered into with regulatory agencies including EPA, BSEE, OSHA, and state regulators. Tracks issuing agency, violation basis, agreed remediation actions, penalty amounts, compliance milestones, reporting obligations imposed by the order, and current fulfillment status.';

CREATE OR REPLACE TABLE `oil_gas_ecm`.`compliance`.`regulatory_penalty` (
    `regulatory_penalty_id` BIGINT COMMENT 'Unique surrogate identifier for each regulatory penalty record in the Oil Gas compliance system. Primary key for the regulatory_penalty data product.',
    `asset_facility_id` BIGINT COMMENT 'Reference to the facility, plant, terminal, or operational site where the violation occurred that resulted in the penalty (e.g., refinery, processing plant, offshore platform, pipeline segment).',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Penalties require cost center allocation for budget tracking, variance analysis, and departmental accountability. Real business process: penalty accrual, payment tracking, and budget impact analysis i',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Penalties require GL account mapping for accrual posting, payment clearing, and financial statement preparation. Links assessed_amount, settled_amount, and paid_amount to proper liability and expense ',
    `obligation_id` BIGINT COMMENT 'Reference to the compliance obligation that was violated, linking the penalty to the specific regulatory requirement that triggered it.',
    `permit_id` BIGINT COMMENT 'Reference to the permit associated with the violation, applicable when the penalty arises from a permit condition breach (e.g., emission limit exceedance under an EPA air permit).',
    `petroleum_product_id` BIGINT COMMENT 'Foreign key linking to product.petroleum_product. Business justification: Penalties assessed for product-specific violations: off-spec fuel sales, contaminated product releases, mislabeled products, or unauthorized product marketing. Product identification enables penalty c',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Penalties impact segment profitability and must be allocated to profit centers for accurate segment P&L, performance measurement, and financial statement segment reporting. Essential for management ac',
    `regulatory_authority_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_authority. Business justification: A regulatory penalty is assessed by a specific regulatory authority (e.g., EPA assesses Clean Air Act penalties, BSEE assesses offshore safety penalties). The regulatory_penalty table has assessing_au',
    `well_asset_id` BIGINT COMMENT 'Foreign key linking to asset.well_asset. Business justification: Penalties are assessed against specific wells (e.g., well integrity violations, spill penalties, UIC violations). regulatory_penalty has well_api_number as a denormalized text field; replacing with we',
    `accrual_amount` DECIMAL(18,2) COMMENT 'Amount accrued in the financial statements for this penalty under IFRS/GAAP contingent liability provisions. May differ from assessed or settled amounts based on probability-weighted estimates. Supports SOX financial controls and SEC disclosure.',
    `appeal_decision_date` DATE COMMENT 'Date on which the regulatory authority or administrative tribunal issued its final decision on the appeal. Triggers update to settled_amount and penalty_status.',
    `appeal_filed_date` DATE COMMENT 'Date on which the company formally filed an appeal or contest against the penalty assessment with the regulatory authority or administrative tribunal.',
    `appeal_status` STRING COMMENT 'Current status of any formal appeal or contest filed against the penalty assessment. Determines whether the settled_amount may change and affects financial accrual estimates under IFRS IAS 37 / ASC 450.. Valid values are `not_appealed|appeal_filed|appeal_pending|appeal_granted|appeal_denied|withdrawn`',
    `assessed_amount` DECIMAL(18,2) COMMENT 'Gross monetary penalty amount originally assessed by the regulatory authority before any reductions, waivers, or negotiated settlements. Used as the basis for financial accrual and liability disclosure.',
    `assessment_date` DATE COMMENT 'Date on which the regulatory authority formally assessed and issued the penalty notice or order. Serves as the principal business event date for the penalty lifecycle and triggers payment due date calculation.',
    `authority_case_number` STRING COMMENT 'Internal case or docket number assigned by the assessing regulatory authority for tracking the enforcement action in their system (distinct from the company-assigned penalty_number).',
    `corrective_action_due_date` DATE COMMENT 'Date by which the mandated corrective action plan must be completed and demonstrated to the regulatory authority. Applicable when corrective_action_required is true.',
    `corrective_action_required` BOOLEAN COMMENT 'Indicates whether the regulatory authority has mandated a corrective action plan (CAP) or supplemental environmental project (SEP) as a condition of the penalty settlement or consent order.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code for the jurisdiction where the violation occurred (e.g., USA, GBR, NGA). Supports multinational regulatory liability reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this regulatory penalty record was first created in the compliance management system. Supports audit trail and SOX internal controls.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this penalty record (e.g., USD, GBP, EUR). Supports multinational financial reporting and currency conversion.. Valid values are `^[A-Z]{3}$`',
    `enablon_incident_ref` STRING COMMENT 'Reference identifier from the Enablon HSE Management system for the incident or non-compliance event that triggered this penalty. Enables cross-system traceability between HSE incident management and regulatory enforcement.',
    `facility_name` STRING COMMENT 'Name of the facility, plant, or operational site where the violation occurred. Retained as a denormalized field for reporting and regulatory submissions without requiring a join.',
    `ghg_related` BOOLEAN COMMENT 'Indicates whether the penalty is related to a Greenhouse Gas (GHG) emission violation (e.g., methane flaring exceedance, GHG reporting failure). Supports ESG reporting and carbon liability disclosure.',
    `hse_classification` STRING COMMENT 'Health, Safety, and Environment (HSE) classification of the penalty, indicating whether it relates to an environmental, occupational safety, health, process safety, or security violation. Supports ESG reporting and HSE performance metrics.. Valid values are `environmental|safety|health|process_safety|security`',
    `is_sec_reportable` BOOLEAN COMMENT 'Indicates whether this penalty meets the materiality threshold requiring disclosure in SEC filings (10-K, 10-Q) under SEC Regulation S-K Item 103 (Legal Proceedings). Supports SOX compliance and investor relations.',
    `jurisdiction_level` STRING COMMENT 'Level of government jurisdiction under which the penalty was assessed. Determines applicable legal framework, appeal venue, and disclosure requirements.. Valid values are `federal|state|local|international`',
    `paid_amount` DECIMAL(18,2) COMMENT 'Actual monetary amount paid to the regulatory authority to date. May be less than settled_amount if payment is in installments or partially paid. Supports cash flow reporting and accounts payable reconciliation.',
    `payment_date` DATE COMMENT 'Actual date on which the penalty payment was remitted to the regulatory authority. Used to confirm timely payment and close the penalty record.',
    `payment_due_date` DATE COMMENT 'Date by which the penalty payment must be remitted to the regulatory authority to avoid additional interest, late fees, or escalated enforcement. Drives accounts payable scheduling.',
    `payment_status` STRING COMMENT 'Current payment status of the penalty amount. Drives accounts payable follow-up, interest accrual, and regulatory relationship management.. Valid values are `unpaid|partial|paid|overdue|waived`',
    `penalty_number` STRING COMMENT 'Externally assigned penalty or civil penalty case number issued by the regulatory authority (e.g., EPA enforcement case number, BSEE incident of non-compliance number, PHMSA penalty order number). Used for correspondence and regulatory tracking.',
    `penalty_status` STRING COMMENT 'Current lifecycle status of the regulatory penalty. Drives financial accrual decisions and regulatory liability disclosure. [ENUM-REF-CANDIDATE: assessed|contested|settled|paid|waived|appealed|closed — promote to reference product]',
    `penalty_title` STRING COMMENT 'Short descriptive title of the penalty or enforcement action as designated by the assessing regulatory authority (e.g., Notice of Violation - Flaring Exceedance, Civil Penalty Order - Pipeline Integrity).',
    `regulation_citation` STRING COMMENT 'Specific regulatory citation, statute, or code section under which the penalty was assessed (e.g., Clean Air Act Section 113(b), 30 CFR Part 250, 49 CFR Part 195). Supports legal defense and compliance gap analysis.',
    `regulation_name` STRING COMMENT 'Full name of the regulation, rule, or statute under which the penalty was assessed (e.g., Clean Air Act, Clean Water Act, Pipeline Safety Improvement Act, Outer Continental Shelf Lands Act).',
    `repeat_violation` BOOLEAN COMMENT 'Indicates whether this penalty arises from a repeat violation of the same regulation or permit condition within a defined lookback period. Repeat violations typically attract higher penalty multipliers and heightened regulatory scrutiny.',
    `responsible_business_unit` STRING COMMENT 'Name of the business unit or division within Oil Gas that is accountable for the violation and responsible for penalty payment and corrective action (e.g., Upstream E&P, Refining, Midstream, Petrochemicals).',
    `sap_document_number` STRING COMMENT 'SAP S/4HANA FI module document number for the financial posting (accrual or payment) associated with this penalty. Enables reconciliation between the compliance register and the general ledger.',
    `settled_amount` DECIMAL(18,2) COMMENT 'Final negotiated or adjudicated penalty amount agreed upon after appeal, mitigation, or settlement proceedings. May differ from assessed_amount due to reductions granted by the authority. Used for final financial accrual and SEC disclosure.',
    `state_code` STRING COMMENT 'Two-letter US state code for the jurisdiction where the violation occurred and penalty was assessed. Applicable for state-level enforcement actions.. Valid values are `^[A-Z]{2}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this regulatory penalty record was last modified in the compliance management system. Supports change tracking, audit trail, and SOX internal controls.',
    CONSTRAINT pk_regulatory_penalty PRIMARY KEY(`regulatory_penalty_id`)
) COMMENT 'Transactional record of monetary penalties, fines, and civil penalties assessed by regulatory authorities for compliance violations. Tracks penalty amount, assessing authority, violation basis, assessment date, payment due date, payment status, appeal status, and final settled amount. Supports financial accrual reporting and regulatory liability disclosure.';

CREATE OR REPLACE TABLE `oil_gas_ecm`.`compliance`.`certification` (
    `certification_id` BIGINT COMMENT 'Unique surrogate identifier for the compliance certification record in the Oil Gas enterprise data platform.',
    `afe_budget_id` BIGINT COMMENT 'Foreign key linking to procurement.afe_budget. Business justification: Compliance certifications (ISO 9001, ISO 14001, SEMS) for facilities and projects incur costs (auditor fees, consulting, implementation) charged to project AFE budgets. This link enables tracking cert',
    `asset_facility_id` BIGINT COMMENT 'Reference to the primary facility, plant, platform, or operational site covered by this certification. Links to the asset management or facility master record.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Certifications (ISO 14001, SEMS, API Q1) are issued to legal entities (accounts). Real process: entity certification tracking for vendor qualification, operator certification requirements, and determi',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Certification bodies (ISO registrars, API auditors) are vendors providing certification audit services. Real business process: certification services procurement. Replaces text certifying_body with FK',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Certification fees and audit costs are allocated to facility or compliance cost centers for operational budgeting. Links certification_fee_amount to cost objects for variance analysis and joint ventur',
    `counterparty_id` BIGINT COMMENT 'Foreign key linking to customer.customer_counterparty. Business justification: Counterparties hold certifications as operators or service providers. Real process: tracking counterparty certifications for operator qualification, JV partner vetting, and verifying that counterparti',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: Certifications are often required to fulfill specific regulatory compliance obligations (e.g., ISO 14001 for environmental compliance, API certifications for safety). Adding obligation_id FK links the',
    `operating_license_id` BIGINT COMMENT 'Foreign key linking to compliance.operating_license. Business justification: A compliance certification may be required as a condition of an operating license (e.g., an offshore operating license requiring SEMS certification, a pipeline operating license requiring operator qua',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: A compliance certification may be required as a condition of a specific permit (e.g., an air permit requiring ISO 14001 certification, a BOEM permit requiring SEMS certification). Linking compliance_c',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Certifications (ISO, SEMS, API) are obtained for specific operating segments/profit centers; certification costs and maintenance expenses must be allocated to profit centers for accurate segment P&L a',
    `regulatory_authority_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_authority. Business justification: A compliance certification is issued or recognized by a specific regulatory authority or governing body (e.g., ISO certifications recognized by EPA, SEMS certifications recognized by BSEE). The compli',
    `well_asset_id` BIGINT COMMENT 'Foreign key linking to asset.well_asset. Business justification: Well certifications (mechanical integrity certifications, well control certifications, BSEE SEMS well certifications) are issued for specific wells. compliance_certification links to asset_facility bu',
    `audit_cycle_years` STRING COMMENT 'The standard recertification or surveillance audit cycle in years as defined by the certifying body (e.g., 3 years for ISO management system certifications with annual surveillance audits).',
    `business_unit` STRING COMMENT 'The organizational business unit or division responsible for maintaining and renewing this certification (e.g., Upstream Gulf of Mexico, Downstream Refining, Midstream Pipeline Operations, Petrochemicals).',
    `certificate_document_ref` STRING COMMENT 'Reference path, document management system ID, or URL to the scanned or digital copy of the official certificate document issued by the certifying body. Supports audit trail and regulatory inspection readiness.',
    `certification_number` STRING COMMENT 'Externally-known alphanumeric identifier assigned by the certifying body or internal compliance system to uniquely reference this certification (e.g., API-2024-00123, ISO14001-CERT-0045, BSEE-SEMS-2024-001).',
    `certification_status` STRING COMMENT 'Current lifecycle state of the certification. active indicates the certification is valid and in force; expired indicates the certification has passed its expiration date without renewal; suspended indicates temporary withdrawal by the certifying body; revoked indicates permanent cancellation; pending_renewal indicates renewal is in progress; withdrawn indicates voluntary surrender.. Valid values are `active|expired|suspended|revoked|pending_renewal|withdrawn`',
    `certification_type` STRING COMMENT 'High-level classification of the certification by its governing domain (e.g., management_system for ISO certifications, regulatory_attestation for BSEE/BOEM, financial_attestation for SOX CEO/CFO, operator_qualification for pipeline operator qualifications). [ENUM-REF-CANDIDATE: management_system|operator_qualification|regulatory_attestation|financial_attestation|api_standard|pipeline_safety|environmental|hse|other — promote to reference product]',
    `certifying_auditor_name` STRING COMMENT 'Name of the lead auditor or assessor from the certifying body who conducted the certification audit or assessment.',
    `certifying_body_accreditation` STRING COMMENT 'Accreditation number or reference of the certifying body issued by an accreditation authority (e.g., ANAB, UKAS, DAkkS accreditation number), confirming the certifying body is authorized to issue the certification standard.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the jurisdiction in which the certification is applicable or was issued (e.g., USA, GBR, NLD, SAU, NGA).. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this certification record was first created in the enterprise data platform. Supports audit trail and data lineage requirements.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the certification fee amount (e.g., USD, EUR, GBP, SAR). Supports multi-currency financial reporting for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `enablon_cert_ref` STRING COMMENT 'Reference identifier for this certification record in the Enablon HSE Management system, enabling traceability between the enterprise data platform and the operational HSE system of record.',
    `esg_reporting_flag` BOOLEAN COMMENT 'Indicates whether this certification is referenced in or supports the companys Environmental, Social, and Governance (ESG) reporting disclosures (e.g., ISO 14001 certification cited in ESG report, GHG verification certifications).',
    `expiration_date` DATE COMMENT 'The date on which the certification expires and is no longer valid unless renewed. Null for certifications with no defined expiry (e.g., certain SOX attestations). Used to drive renewal workflows and compliance calendar alerts.',
    `fee_amount` DECIMAL(18,2) COMMENT 'The fee paid to the certifying body for the initial certification or most recent renewal audit, expressed in the currency defined by currency_code. Used for OPEX budgeting and cost tracking.',
    `ghg_related` BOOLEAN COMMENT 'Indicates whether this certification is related to Greenhouse Gas (GHG) emissions verification, carbon accounting, or climate-related compliance (e.g., ISO 14064 GHG verification, EPA GHG Reporting Program certifications).',
    `hse_classification` STRING COMMENT 'Classifies the certification by its Health, Safety, and Environment (HSE) domain. environmental for ISO 14001 and EPA-related certifications; occupational_health_safety for ISO 45001 and OSHA certifications; process_safety for API RP 750/OSHA PSM certifications; combined_hse for integrated management system certifications; not_applicable for financial or non-HSE certifications.. Valid values are `environmental|occupational_health_safety|process_safety|combined_hse|not_applicable`',
    `issue_date` DATE COMMENT 'The date on which the certifying body formally issued or granted the certification. Represents the start of the certifications validity period.',
    `last_audit_date` DATE COMMENT 'Date of the most recent surveillance, recertification, or assessment audit conducted by the certifying body against this certification standard.',
    `major_nonconformance_count` STRING COMMENT 'Number of major nonconformances identified during the most recent certification audit. Major nonconformances typically require resolution before the certificate can be issued or maintained.',
    `next_audit_date` DATE COMMENT 'Date of the next planned surveillance or recertification audit scheduled by the certifying body. Used to drive compliance calendar planning and resource allocation.',
    `nonconformance_count` STRING COMMENT 'Number of nonconformances or findings identified during the most recent certification audit. Major and minor nonconformances must be resolved before or after certification issuance per certifying body requirements.',
    `offshore_indicator` BOOLEAN COMMENT 'Indicates whether this certification applies to offshore operations (True) or onshore operations (False). Offshore certifications are subject to BSEE/BOEM jurisdiction and additional regulatory requirements.',
    `operator_qualification_flag` BOOLEAN COMMENT 'Indicates whether this certification is an Operator Qualification (OQ) certification for pipeline operations personnel, as required by PHMSA regulations for covered tasks on pipeline facilities.',
    `regulatory_submission_date` DATE COMMENT 'Date on which the certification or evidence of certification was submitted to the relevant regulatory authority. Null if regulatory_submission_required is False or submission has not yet occurred.',
    `regulatory_submission_required` BOOLEAN COMMENT 'Indicates whether this certification or evidence of its maintenance must be formally submitted to a regulatory authority (e.g., BSEE SEMS certification submission, SEC SOX certifications filed with annual reports).',
    `renewal_due_date` DATE COMMENT 'The date by which the renewal application or re-certification audit must be initiated or completed to maintain continuous certification coverage. Typically set ahead of the expiration date based on certifying body requirements.',
    `renewal_status` STRING COMMENT 'Current status of the renewal process for this certification. not_required for certifications that do not expire; pending when renewal has not yet been initiated; in_progress when the renewal audit or application is underway; submitted when the renewal application has been filed; approved when renewal is confirmed; rejected when renewal was denied.. Valid values are `not_required|pending|in_progress|submitted|approved|rejected`',
    `scope_description` STRING COMMENT 'Narrative description of the organizational scope, geographic boundaries, operational activities, and processes covered by the certification (e.g., Offshore drilling operations in Gulf of Mexico including platforms A, B, C, Refinery crude distillation and hydrodesulfurization units at Baytown facility).',
    `sems_applicable` BOOLEAN COMMENT 'Indicates whether this certification is associated with the BSEE Safety and Environmental Management System (SEMS) program applicable to offshore oil and gas operations on the U.S. Outer Continental Shelf.',
    `sox_control_flag` BOOLEAN COMMENT 'Indicates whether this certification is directly associated with a Sarbanes-Oxley (SOX) internal control requirement, such as CEO/CFO Section 302 or Section 906 certifications, or certifications supporting SOX financial reporting controls.',
    `standard` STRING COMMENT 'The specific standard, regulation, or framework against which the certification is issued (e.g., ISO 14001:2015, ISO 45001:2018, ISO 55001:2014, API RP 75, BSEE SEMS, SOX Section 302, PHMSA OQ, OSHA PSM 29 CFR 1910.119).',
    `state_province_code` STRING COMMENT 'State or province code where the certification applies, using ISO 3166-2 subdivision codes (e.g., US-TX for Texas, US-LA for Louisiana). Relevant for state-level regulatory certifications.',
    `title` STRING COMMENT 'Human-readable name or title of the certification (e.g., ISO 14001:2015 Environmental Management System Certification, BSEE Safety and Environmental Management System Certification, SOX CEO/CFO Section 302 Certification).',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this certification record was most recently modified in the enterprise data platform. Supports change tracking and audit trail requirements.',
    CONSTRAINT pk_certification PRIMARY KEY(`certification_id`)
) COMMENT 'Master record of compliance certifications, attestations, and declarations submitted to regulatory bodies or maintained internally. Includes API certifications, ISO 14001 and ISO 45001 certifications, BSEE SEMS certifications, pipeline operator qualifications, and SOX CEO/CFO certifications. Tracks certifying body, certification standard, scope, issue date, expiration date, and renewal status.';

CREATE OR REPLACE TABLE `oil_gas_ecm`.`compliance`.`regulatory_authority` (
    `regulatory_authority_id` BIGINT COMMENT 'Primary key for regulatory_authority',
    `parent_regulatory_authority_id` BIGINT COMMENT 'Self-referencing FK on regulatory_authority (parent_regulatory_authority_id)',
    `abbreviation` STRING COMMENT 'Common short form or acronym used for the authority.',
    `active_status` STRING COMMENT 'Current operational status of the authority.',
    `address` STRING COMMENT 'Physical mailing address of the authoritys main office.',
    `authority_type` STRING COMMENT 'Classification of the authority by its governance level.',
    `compliance_scope` STRING COMMENT 'Primary regulatory domain(s) the authority oversees.',
    `contact_email` STRING COMMENT 'Primary public email address for contacting the authority.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the authority record was first created in the system.',
    `data_submission_method` STRING COMMENT 'Preferred method for submitting data to the authority.',
    `effective_date` DATE COMMENT 'Date when the authority became effective or was recognized.',
    `jurisdiction` STRING COMMENT 'ISO‑3 country code of the primary jurisdiction the authority covers.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the authority record.',
    `phone_number` STRING COMMENT 'Public telephone number for the authority.',
    `regulatory_authority_description` STRING COMMENT 'Free‑form description of the authoritys mandate and responsibilities.',
    `regulatory_authority_name` STRING COMMENT 'Official full name of the regulatory authority (e.g., Environmental Protection Agency).',
    `regulatory_body_code` STRING COMMENT 'Internal or industry code used to reference the authority.',
    `reporting_frequency` STRING COMMENT 'Typical frequency at which the authority requires regulatory submissions.',
    `termination_date` DATE COMMENT 'Date the authority ceased operations, if applicable.',
    `website_url` STRING COMMENT 'Public website address for the regulatory authority.',
    CONSTRAINT pk_regulatory_authority PRIMARY KEY(`regulatory_authority_id`)
) COMMENT 'Master reference table for regulatory_authority. Referenced by regulatory_authority_id.';

